var surah026 = {
  number: 26,
  nameArabic: "Ash-Shu'ara",
  nameEnglish: "Ash-Shu'ara",
  meaning: "The Poets",
  totalAyahs: 227,
  ayahs: [
    { number: 1, arabic: "طسٓمٓ", transliteration: "Taseenmeem", transliterationB: "Taa-Seeen-Meeem", english: "Ta. Sin. Mim", romanUrdu: "Taa seen Meem" },
    { number: 2, arabic: "تِلْكَ ءَايَٰتُ ٱلْكِتَٰبِ ٱلْمُبِينِ", transliteration: "Tilka ayatu alkitabi almubeeni", transliterationB: "Tilka Aayaatul Kitaabil Mubeen", english: "These are verses of the Book that makes (things) clear", romanUrdu: "Yeh kitaab e Mubeen ki aayat hain" },
    { number: 3, arabic: "لَعَلَّكَ بَٰخِعٌۭ نَّفْسَكَ أَلَّا يَكُونُوا۟ مُؤْمِنِينَ", transliteration: "LaAAallaka bakhiAAun nafsaka alla yakoonoo mumineena", transliterationB: "La'allaka baakhi'un nafsaka allaa yakoonoo mu'mineen", english: "It may be thou frettest thy soul with grief, that they do not become Believers", romanUrdu: "(Aey Muhammad), shayad tum is gham (grief) mein apni jaan kho dogey ke yeh log iman nahin latey" },
    { number: 4, arabic: "إِن نَّشَأْ نُنَزِّلْ عَلَيْهِم مِّنَ ٱلسَّمَآءِ ءَايَةًۭ فَظَلَّتْ أَعْنَٰقُهُمْ لَهَا خَٰضِعِينَ", transliteration: "In nasha nunazzil AAalayhim mina alssamai ayatan fathallat aAAnaquhum laha khadiAAeena", transliterationB: "In nashaa nunazzil 'alaihim minas samaaa'i Aayatan fazallat a'naaquhum lahaa khaadi'een", english: "If (such) were Our Will, We could send down to them from the sky a Sign, to which they would bend their necks in humility", romanUrdu: "Hum chahein to aasmaan se aisi nishani nazil kar sakte hain ke inki gardanein iske aagey jhuk jayein" },
    { number: 5, arabic: "وَمَا يَأْتِيهِم مِّن ذِكْرٍۢ مِّنَ ٱلرَّحْمَٰنِ مُحْدَثٍ إِلَّا كَانُوا۟ عَنْهُ مُعْرِضِينَ", transliteration: "Wama yateehim min thikrin mina alrrahmani muhdathin illa kanoo AAanhu muAArideena", transliterationB: "Wa maa yaateehim min zikrim minar Rahmaani muhdasin illaa kaanoo 'anhu mu'rideen", english: "But there comes not to them a newly-revealed Message from (Allah) Most Gracious, but they turn away therefrom", romanUrdu: "In logon ke paas rehman ki taraf se jo nayi naseehat bhi aati hai yeh ussey mooh moad letey hain" },
    { number: 6, arabic: "فَقَدْ كَذَّبُوا۟ فَسَيَأْتِيهِمْ أَنۢبَٰٓؤُا۟ مَا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ", transliteration: "Faqad kaththaboo fasayateehim anbao ma kanoo bihi yastahzioona", transliterationB: "Faqad kazzaboo fasa yaateehim ambaaa'u maa kaanoo bihee yastahzi'oon", english: "They have indeed rejected (the Message): so they will know soon (enough) the truth of what they mocked at", romanUrdu: "Ab ke yeh jhutla chuke hain, ankareeb inko is cheez ki haqeeqat (mukhtalif tareeqon se) maloom ho jayegi jiska yeh mazaak udatay rahey hain" },
    { number: 7, arabic: "أَوَلَمْ يَرَوْا۟ إِلَى ٱلْأَرْضِ كَمْ أَنۢبَتْنَا فِيهَا مِن كُلِّ زَوْجٍۢ كَرِيمٍ", transliteration: "Awalam yaraw ila alardi kam anbatna feeha min kulli zawjin kareemin", transliterationB: "Awa lam yaraw ilal ardi kam ambatnaa feehaa min kulli zawjin kareem", english: "Do they not look at the earth,- how many noble things of all kinds We have produced therein", romanUrdu: "Aur kya inhon ne kabhi zameen par nigaah nahin daali ke humne kitni kaseer miqdaar mein har tarah ki umdah nabataat(vegetation) ismein paida ki hain" },
    { number: 8, arabic: "إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ", transliteration: "Inna fee thalika laayatan wama kana aktharuhum mumineena", transliterationB: "Inn fee zaalika la Aayah; wa maa kaana aksaruhum mu'mineen", english: "Verily, in this is a Sign: but most of them do not believe", romanUrdu: "Yaqeenen ismein ek nishani hai, magar in mein se aksar maanne waley nahin" },
    { number: 9, arabic: "وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ", transliteration: "Wainna rabbaka lahuwa alAAazeezu alrraheemu", transliterationB: "Wa inna Rabbaka la Huwal 'Azeezur Raheem", english: "And verily, thy Lord is He, the Exalted in Might, Most Merciful", romanUrdu: "Aur haqeeqat yeh hai ke tera Rubb zabardast bhi hai aur raheem bhi" },
    { number: 10, arabic: "وَإِذْ نَادَىٰ رَبُّكَ مُوسَىٰٓ أَنِ ٱئْتِ ٱلْقَوْمَ ٱلظَّٰلِمِينَ", transliteration: "Waith nada rabbuka moosa ani iti alqawma alththalimeena", transliterationB: "Wa iz naadaa Rabbuka Moosaaa ani'-til qawmaz zaalimeen", english: "Behold, thy Lord called Moses: \"Go to the people of iniquity", romanUrdu: "Inhein us waqt ka qissa sunao jabke tumhare Rubb ne Moosa ko pukara “ zaalim qaum ke paas jaa" },
    { number: 11, arabic: "قَوْمَ فِرْعَوْنَ ۚ أَلَا يَتَّقُونَ", transliteration: "Qawma firAAawna ala yattaqoona", transliterationB: "Qawma Fir'awn; alaa yattaqoon", english: "The people of the Pharaoh: will they not fear Allah", romanUrdu: "Firoun ki qaum ke paas, kya woh nahin darte?”" },
    { number: 12, arabic: "قَالَ رَبِّ إِنِّىٓ أَخَافُ أَن يُكَذِّبُونِ", transliteration: "Qala rabbi innee akhafu an yukaththibooni", transliterationB: "Qaala Rabbi inneee akhaafu ai yukazziboon", english: "He said: \"O my Lord! I do fear that they will charge me with falsehood", romanUrdu: "Usne arz kiya “aey Rubb, mujhey khauf hai ke woh mujhey jhutla dengey" },
    { number: 13, arabic: "وَيَضِيقُ صَدْرِى وَلَا يَنطَلِقُ لِسَانِى فَأَرْسِلْ إِلَىٰ هَٰرُونَ", transliteration: "Wayadeequ sadree wala yantaliqu lisanee faarsil ila haroona", transliterationB: "Wa yadeequ sadree wa laa yantaliqu lisaanee fa arsil ilaa Haaroon", english: "My breast will be straitened. And my speech may not go (smoothly): so send unto Aaron", romanUrdu: "Mera seena ghutt-ta hai aur meri zubaan nahin chalti, aap Haroon ki taraf risalat bhejein" },
    { number: 14, arabic: "وَلَهُمْ عَلَىَّ ذَنۢبٌۭ فَأَخَافُ أَن يَقْتُلُونِ", transliteration: "Walahum AAalayya thanbun faakhafu an yaqtulooni", transliterationB: "Wa lahum 'alaiya zambun fa akhaafu ai yaqtuloon", english: "And (further), they have a charge of crime against me; and I fear they may slay me", romanUrdu: "Aur mujhpar unke haan ek jurm ka ilzam bhi hai, is liye main darta hoon ke woh mujhey qatal kar dengey”" },
    { number: 15, arabic: "قَالَ كَلَّا ۖ فَٱذْهَبَا بِـَٔايَٰتِنَآ ۖ إِنَّا مَعَكُم مُّسْتَمِعُونَ", transliteration: "Qala kalla faithhaba biayatina inna maAAakum mustamiAAoona", transliterationB: "Qaala kallaa fazhabaa bi Aayaatinaaa innaa ma'akum mustami'oon", english: "Allah said: \"By no means! proceed then, both of you, with Our Signs; We are with you, and will listen (to your call)", romanUrdu: "Farmaya “hargiz nahin, tum dono jao hamari nishaniyan lekar, hum tumhare saath sab kuch suntey rahenge" },
    { number: 16, arabic: "فَأْتِيَا فِرْعَوْنَ فَقُولَآ إِنَّا رَسُولُ رَبِّ ٱلْعَٰلَمِينَ", transliteration: "Fatiya firAAawna faqoola inna rasoolu rabbi alAAalameena", transliterationB: "Faatiyaa Fir'awna faqoolaaa innaa Rasoolu Rabbil 'aalameen", english: "So go forth, both of you, to Pharaoh, and say: 'We have been sent by the Lord and Cherisher of the worlds", romanUrdu: "Firoun ke paas jao aur ussey kaho, humko Rubb ul aalameen ne isliye bheja hai" },
    { number: 17, arabic: "أَنْ أَرْسِلْ مَعَنَا بَنِىٓ إِسْرَٰٓءِيلَ", transliteration: "An arsil maAAana banee israeela", transliterationB: "An arsil ma'anaa Baneee Israaa'eel", english: "Send thou with us the Children of Israel", romanUrdu: "Ke tu bani Israel ko hamare saath janey de”" },
    { number: 18, arabic: "قَالَ أَلَمْ نُرَبِّكَ فِينَا وَلِيدًۭا وَلَبِثْتَ فِينَا مِنْ عُمُرِكَ سِنِينَ", transliteration: "Qala alam nurabbika feena waleedan walabithta feena min AAumurika sineena", transliterationB: "Qaala alam nurabbika feenaa waleedanw wa labista feenaa min 'umurika sineen", english: "(Pharaoh) said: \"Did we not cherish thee as a child among us, and didst thou not stay in our midst many years of thy life", romanUrdu: "Firoun ne kaha “kya humne tujhko apne haan baccha sa nahin paala tha? Tu nay apni umar ke kai saal hamare haan guzare" },
    { number: 19, arabic: "وَفَعَلْتَ فَعْلَتَكَ ٱلَّتِى فَعَلْتَ وَأَنتَ مِنَ ٱلْكَٰفِرِينَ", transliteration: "WafaAAalta faAAlataka allatee faAAalta waanta mina alkafireena", transliterationB: "Wa fa'alta fa'latakal latee fa'alta wa anta minal kaafireen", english: "And thou didst a deed of thine which (thou knowest) thou didst, and thou art an ungrateful (wretch)", romanUrdu: "Aur iske baad kar gaya jo kuch ke kar gaya, tu bada ehsan faramosh aadmi hai”" },
    { number: 20, arabic: "قَالَ فَعَلْتُهَآ إِذًۭا وَأَنَا۠ مِنَ ٱلضَّآلِّينَ", transliteration: "Qala faAAaltuha ithan waana mina alddalleena", transliterationB: "Qaala fa'altuhaaa izanw wa ana minad daaaleen", english: "Moses said: \"I did it then, when I was in error", romanUrdu: "Moosa ne jawab diya “us waqt woh kaam maine nadanishtagi (inadvertently) mein kardiya tha" },
    { number: 21, arabic: "فَفَرَرْتُ مِنكُمْ لَمَّا خِفْتُكُمْ فَوَهَبَ لِى رَبِّى حُكْمًۭا وَجَعَلَنِى مِنَ ٱلْمُرْسَلِينَ", transliteration: "Fafarartu minkum lamma khiftukum fawahaba lee rabbee hukman wajaAAalanee mina almursaleena", transliterationB: "Fafarartu minkum lam maa khiftukum fawahaba lee Rabbee hukmanw wa ja'alanee minal mursaleen", english: "So I fled from you (all) when I feared you; but my Lord has (since) invested me with judgment (and wisdom) and appointed me as one of the messengers", romanUrdu: "Phir main tumhare khauf se bhaag gaya. Iske baad mere Rubb ne mujhko hukum ata kiya aur mujhey Rasoolon mein shamil farma liya" },
    { number: 22, arabic: "وَتِلْكَ نِعْمَةٌۭ تَمُنُّهَا عَلَىَّ أَنْ عَبَّدتَّ بَنِىٓ إِسْرَٰٓءِيلَ", transliteration: "Watilka niAAmatun tamunnuha AAalayya an AAabbadta banee israeela", transliterationB: "Wa tilka ni'matun tamun nuhaa 'alaiya an 'abbatta Baneee Israaa'eel", english: "And this is the favour with which thou dost reproach me,- that thou hast enslaved the Children of Israel", romanUrdu: "Raha tera ehsan jo tu nay mujhpar jataya hai to iski haqeeqat yeh hai ke tu nay bani Israel ko ghulaam bana liya tha”" },
    { number: 23, arabic: "قَالَ فِرْعَوْنُ وَمَا رَبُّ ٱلْعَٰلَمِينَ", transliteration: "Qala firAAawnu wama rabbu alAAalameena", transliterationB: "Qaala Fir'awnu wa maa Rabbul 'aalameen", english: "Pharaoh said: \"And what is the 'Lord and Cherisher of the worlds", romanUrdu: "Firoun ne kaha “aur yeh Rubb-ul-Aalameen kya hota hai?”" },
    { number: 24, arabic: "قَالَ رَبُّ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَآ ۖ إِن كُنتُم مُّوقِنِينَ", transliteration: "Qala rabbu alssamawati waalardi wama baynahuma in kuntum mooqineena", transliterationB: "Qaala Rabbus samaawaati wal ardi wa maa bainahumaa in kuntum mooqineen", english: "(Moses) said: \"The Lord and Cherisher of the heavens and the earth, and all between,- if ye want to be quite sure", romanUrdu: "Moosa ne jawab diya “Aasmano aur zameen ka Rubb, aur un sab cheezon ka Rubb jo aasmaan o zameen ke darmiyan hain, agar tum yaqeen laney waley ho.”" },
    { number: 25, arabic: "قَالَ لِمَنْ حَوْلَهُۥٓ أَلَا تَسْتَمِعُونَ", transliteration: "Qala liman hawlahu ala tastamiAAoona", transliterationB: "Qaala liman hawlahooo alaa tastami'oon", english: "(Pharaoh) said to those around: \"Did ye not listen (to what he says)", romanUrdu: "Firoun ne apne gird o pesh ke logon se kaha ‘Sunte ho?”" },
    { number: 26, arabic: "قَالَ رَبُّكُمْ وَرَبُّ ءَابَآئِكُمُ ٱلْأَوَّلِينَ", transliteration: "Qala rabbukum warabbu abaikumu alawwaleena", transliterationB: "Qaala Rabbukum wa Rabbu aabaaa'ikumul awwaleen", english: "(Moses) said: \"Your Lord and the Lord of your fathers from the beginning", romanUrdu: "Moosa ne kaha, “tumhara Rubb bhi aur tumhare un aabaa o ajdaad ka Rubb bhi jo guzar chuke hain”" },
    { number: 27, arabic: "قَالَ إِنَّ رَسُولَكُمُ ٱلَّذِىٓ أُرْسِلَ إِلَيْكُمْ لَمَجْنُونٌۭ", transliteration: "Qala inna rasoolakumu allathee orsila ilaykum lamajnoonun", transliterationB: "Qaala inna Rasoolakumul lazee ursila ilaikum lamajnoon", english: "(Pharaoh) said: \"Truly your messenger who has been sent to you is a veritable madman", romanUrdu: "Firoun ne ( haazirin se) kaha “ tumhare yeh Rasool sahib jo tumhari taraf bhejey gaye hain, bilkul hi pagal maloom hotay hain”" },
    { number: 28, arabic: "قَالَ رَبُّ ٱلْمَشْرِقِ وَٱلْمَغْرِبِ وَمَا بَيْنَهُمَآ ۖ إِن كُنتُمْ تَعْقِلُونَ", transliteration: "Qala rabbu almashriqi waalmaghribi wama baynahuma in kuntum taAAqiloona", transliterationB: "Qaala Rabbul mashriqi wal maghribi wa maa baina humaa in kuntum ta'qiloon", english: "(Moses) said: \"Lord of the East and the West, and all between! if ye only had sense", romanUrdu: "Moosa ne kaha “mashriq o magrib aur jo kuch inke darmiyan hai sabka Rubb, agar aap log kuch aqal rakhte hain”" },
    { number: 29, arabic: "قَالَ لَئِنِ ٱتَّخَذْتَ إِلَٰهًا غَيْرِى لَأَجْعَلَنَّكَ مِنَ ٱلْمَسْجُونِينَ", transliteration: "Qala laini ittakhathta ilahan ghayree laajAAalannaka mina almasjooneena", transliterationB: "Qaala la'init takhazta ilaahan ghairee la aj'alannaka minal masjooneen", english: "(Pharaoh) said: \"If thou dost put forward any god other than me, I will certainly put thee in prison", romanUrdu: "Firoun ne kaha “ agar tu nay mere siwa kisi aur ko mabood maana to tujhey main un logon mein shamil kardunga jo qaid khano mein paday saddh(rotting) rahey hain”" },
    { number: 30, arabic: "قَالَ أَوَلَوْ جِئْتُكَ بِشَىْءٍۢ مُّبِينٍۢ", transliteration: "Qala awalaw jituka bishayin mubeenin", transliterationB: "Qaala awalw ji'tuka bishai'im mubeen", english: "(Moses) said: \"Even if I showed you something clear (and) convincing", romanUrdu: "Moosa ne kaha “Agarche main le aaon tere saamne ek sareeh cheez bhi?”" },
    { number: 31, arabic: "قَالَ فَأْتِ بِهِۦٓ إِن كُنتَ مِنَ ٱلصَّٰدِقِينَ", transliteration: "Qala fati bihi in kunta mina alssadiqeena", transliterationB: "Qaala faati biheee in kunta minas saadiqeen", english: "(Pharaoh) said: \"Show it then, if thou tellest the truth", romanUrdu: "Firoun ne kaha “Accha to le aa agar tu saccha hai”" },
    { number: 32, arabic: "فَأَلْقَىٰ عَصَاهُ فَإِذَا هِىَ ثُعْبَانٌۭ مُّبِينٌۭ", transliteration: "Faalqa AAasahu faitha hiya thuAAbanun mubeenun", transliterationB: "Fa alqaa 'asaahu fa izaaa hiya su'baanum mubeen", english: "So (Moses) threw his rod, and behold, it was a serpent, plain (for all to see)", romanUrdu: "(Uski zubaan se yeh baat nikalte hi) Moosa ne apna asa (staff) phenka aur yakayak woh ek sareeh azdha (serpant/snake) tha" },
    { number: 33, arabic: "وَنَزَعَ يَدَهُۥ فَإِذَا هِىَ بَيْضَآءُ لِلنَّٰظِرِينَ", transliteration: "WanazaAAa yadahu faitha hiya baydao lilnnathireena", transliterationB: "Wa naza'a yadahoo faizaa hiya baidaaa'u linnaa zireen", english: "And he drew out his hand, and behold, it was white to all beholders", romanUrdu: "Phir usne apna hath (bagal se) khincha aur wo sab dekne walon ke saamne chamak raha tha" },
    { number: 34, arabic: "قَالَ لِلْمَلَإِ حَوْلَهُۥٓ إِنَّ هَٰذَا لَسَٰحِرٌ عَلِيمٌۭ", transliteration: "Qala lilmalai hawlahu inna hatha lasahirun AAaleemun", transliterationB: "Qaala lilmala-i hawlahooo inna haazaa lasaahirun 'aleem", english: "(Pharaoh) said to the Chiefs around him: \"This is indeed a sorcerer well-versed", romanUrdu: "Firoun apne gird o pesh ke sardaron se bola “yeh shaks yaqeenan ek maahir jaadugar hai" },
    { number: 35, arabic: "يُرِيدُ أَن يُخْرِجَكُم مِّنْ أَرْضِكُم بِسِحْرِهِۦ فَمَاذَا تَأْمُرُونَ", transliteration: "Yureedu an yukhrijakum min ardikum bisihrihi famatha tamuroona", transliterationB: "Yureedu ai yukhrijakum min ardikum bisihrihee famaazaa taamuroon", english: "His plan is to get you out of your land by his sorcery; then what is it ye counsel", romanUrdu: "Chahta hai ke apne jaadu ke zoar se tumko tumhare mulk se nikal de, ab tum batao tum kya hukum dete ho?”" },
    { number: 36, arabic: "قَالُوٓا۟ أَرْجِهْ وَأَخَاهُ وَٱبْعَثْ فِى ٱلْمَدَآئِنِ حَٰشِرِينَ", transliteration: "Qaloo arjih waakhahu waibAAath fee almadaini hashireena", transliterationB: "Qaalooo arjih wa akhaahu wab'as filmadaaa'ini haashireen", english: "They said: \"Keep him and his brother in suspense (for a while), and dispatch to the Cities heralds to collect", romanUrdu: "Unhon ne kaha “ isey aur iske bhai ko rok lijiye aur shehron mein harkare (heralds) bhej dijiye" },
    { number: 37, arabic: "يَأْتُوكَ بِكُلِّ سَحَّارٍ عَلِيمٍۢ", transliteration: "Yatooka bikulli sahharin AAaleemin", transliterationB: "Yaatooka bikulli sah haarin 'aleem", english: "And bring up to thee all (our) sorcerers well-versed", romanUrdu: "Ke har siyane jaadugar ko aapke paas le aayein”" },
    { number: 38, arabic: "فَجُمِعَ ٱلسَّحَرَةُ لِمِيقَٰتِ يَوْمٍۢ مَّعْلُومٍۢ", transliteration: "FajumiAAa alssaharatu limeeqati yawmin maAAloomin", transliterationB: "Fa jumi'as saharatu limeeqaati Yawmim ma'loom", english: "So the sorcerers were got together for the appointment of a day well-known", romanUrdu: "Chunanchey ek roz muqarrar waqt par jaadugar ikatthey karliye gaye" },
    { number: 39, arabic: "وَقِيلَ لِلنَّاسِ هَلْ أَنتُم مُّجْتَمِعُونَ", transliteration: "Waqeela lilnnasi hal antum mujtamiAAoona", transliterationB: "Wa qeela linnaasi hal antum mujtami'oon", english: "And the people were told: \"Are ye (now) assembled", romanUrdu: "Aur logon se kaha gaya “tum ijtima mein chaloge" },
    { number: 40, arabic: "لَعَلَّنَا نَتَّبِعُ ٱلسَّحَرَةَ إِن كَانُوا۟ هُمُ ٱلْغَٰلِبِينَ", transliteration: "LaAAallana nattabiAAu alssaharata in kanoo humu alghalibeena", transliterationB: "La'allanaa nattabi'us saharata in kaanoo humul ghaalibeen", english: "That we may follow the sorcerers (in religion) if they win", romanUrdu: "Shayad ke hum jaadugaron ke deen hi par reh jayein agar woh gaalib rahey”" },
    { number: 41, arabic: "فَلَمَّا جَآءَ ٱلسَّحَرَةُ قَالُوا۟ لِفِرْعَوْنَ أَئِنَّ لَنَا لَأَجْرًا إِن كُنَّا نَحْنُ ٱلْغَٰلِبِينَ", transliteration: "Falamma jaa alssaharatu qaloo lifirAAawna ainna lana laajran in kunna nahnu alghalibeena", transliterationB: "Falammaa jaaa'as saharatu qaaloo li Fir'awna a'inna lanaa la ajjran in kunnaa nahnul ghaalibeen", english: "So when the sorcerers arrived, they said to Pharaoh: \"Of course - shall we have a (suitable) reward if we win", romanUrdu: "Jab jaadugar maidan mein aa gaye to unhon ne Firoun se kaha “humein inaam to milega agar hum gaalib rahey?”" },
    { number: 42, arabic: "قَالَ نَعَمْ وَإِنَّكُمْ إِذًۭا لَّمِنَ ٱلْمُقَرَّبِينَ", transliteration: "Qala naAAam wainnakum ithan lamina almuqarrabeena", transliterationB: "Qaala na'am wa innakum izal laminal muqarrabeen", english: "He said: \"Yea, (and more),- for ye shall in that case be (raised to posts) nearest (to my person)", romanUrdu: "Usne kaha “ haan, aur tum to us waqt muqarrabeen (nearest to me) mein shamil ho jaogey”" },
    { number: 43, arabic: "قَالَ لَهُم مُّوسَىٰٓ أَلْقُوا۟ مَآ أَنتُم مُّلْقُونَ", transliteration: "Qala lahum moosa alqoo ma antum mulqoona", transliterationB: "Qaala lahum Moosaaa alqoo maaa antum mulqoon", english: "Moses said to them: \"Throw ye - that which ye are about to throw", romanUrdu: "Moosa ne kaha “ phenko jo tumhein phenkna hai”" },
    { number: 44, arabic: "فَأَلْقَوْا۟ حِبَالَهُمْ وَعِصِيَّهُمْ وَقَالُوا۟ بِعِزَّةِ فِرْعَوْنَ إِنَّا لَنَحْنُ ٱلْغَٰلِبُونَ", transliteration: "Faalqaw hibalahum waAAisiyyahum waqaloo biAAizzati firAAawna inna lanahnu alghaliboona", transliterationB: "Fa alqaw hibaalahum wa 'isiyyahum wa qaaloo bi'izzati Fir'awna innaa lanahnul ghaaliboon", english: "So they threw their ropes and their rods, and said: \"By the might of Pharaoh, it is we who will certainly win", romanUrdu: "Unhon ne fawran apni rassiyan aur laathiyan phenk di aur bole “ Firoun ke iqbal se hum hi gaalib rahenge.”" },
    { number: 45, arabic: "فَأَلْقَىٰ مُوسَىٰ عَصَاهُ فَإِذَا هِىَ تَلْقَفُ مَا يَأْفِكُونَ", transliteration: "Faalqa moosa AAasahu faitha hiya talqafu ma yafikoona", transliterationB: "Fa alqaa Moosaa 'asaahu fa izaa hiya talqafu maa yaafikoon", english: "Then Moses threw his rod, when, behold, it straightway swallows up all the falsehoods which they fake", romanUrdu: "Phir Moosa ne apna asa (staff) phenka to yakayak woh unke jhootey karishmon ko hadap karta chala ja raha tha" },
    { number: 46, arabic: "فَأُلْقِىَ ٱلسَّحَرَةُ سَٰجِدِينَ", transliteration: "Faolqiya alssaharatu sajideena", transliterationB: "Fa ulqiyas saharatu saajideen", english: "Then did the sorcerers fall down, prostrate in adoration", romanUrdu: "Ispar sarey jaadugar be-ikhtiyar sajde mein gir paday" },
    { number: 47, arabic: "قَالُوٓا۟ ءَامَنَّا بِرَبِّ ٱلْعَٰلَمِينَ", transliteration: "Qaloo amanna birabbi alAAalameena", transliterationB: "Qaalooo aamannaa bi Rabbil 'aalameen", english: "Saying: \"We believe in the Lord of the Worlds", romanUrdu: "Aur bol uthey ke “ maan gaye hum Rubb-ul-Aalameen ko" },
    { number: 48, arabic: "رَبِّ مُوسَىٰ وَهَٰرُونَ", transliteration: "Rabbi moosa waharoona", transliterationB: "Rabbi Moosaa wa Haaroon", english: "The Lord of Moses and Aaron", romanUrdu: "Moosa aur Haroon ke Rubb ko”" },
    { number: 49, arabic: "قَالَ ءَامَنتُمْ لَهُۥ قَبْلَ أَنْ ءَاذَنَ لَكُمْ ۖ إِنَّهُۥ لَكَبِيرُكُمُ ٱلَّذِى عَلَّمَكُمُ ٱلسِّحْرَ فَلَسَوْفَ تَعْلَمُونَ ۚ لَأُقَطِّعَنَّ أَيْدِيَكُمْ وَأَرْجُلَكُم مِّنْ خِلَٰفٍۢ وَلَأُصَلِّبَنَّكُمْ أَجْمَعِينَ", transliteration: "Qala amantum lahu qabla an athana lakum innahu lakabeerukumu allathee AAallamakumu alssihra falasawfa taAAlamoona laoqattiAAanna aydiyakum waarjulakum min khilafin walaosallibannakum ajmaAAeena", transliterationB: "Qaala aamantum lahoo qabla an aazana lakum innahoo lakabeerukumul lazee 'alla makumus sihra falasawfa ta'lamoon; la uqatti'anna aidiyakum wa arjulakum min khilaafinw wa la usallibanna kum ajma'een", english: "Said (Pharaoh): \"Believe ye in Him before I give you permission? surely he is your leader, who has taught you sorcery! but soon shall ye know! Be sure I will cut off your hands and your feet on opposite sides, and I will cause you all to die on the cross", romanUrdu: "Firoun ne kaha “tum Moosa ki baat maan gaye qabl iske ke main tumhein ijazat deta! Zaroor yeh tumhara bada hai jisne tumhein jaadu sikhaya hai. Accha, abhi tumhein maloom hua jaata hai, main tumhare haath paon mukhalif simton (opposite sides) mein katwaunga aur tum sabko sooli (crucify) chadha dunga”" },
    { number: 50, arabic: "قَالُوا۟ لَا ضَيْرَ ۖ إِنَّآ إِلَىٰ رَبِّنَا مُنقَلِبُونَ", transliteration: "Qaloo la dayra inna ila rabbina munqaliboona", transliterationB: "Qaaloo la daira innaaa ilaa Rabbinaa munqalliboon", english: "They said: \"No matter! for us, we shall but return to our Lord", romanUrdu: "Unhon ne jawab diya “kuch parwah nahin, hum apne Rubb ke huzur pahunch jayenge" },
    { number: 51, arabic: "إِنَّا نَطْمَعُ أَن يَغْفِرَ لَنَا رَبُّنَا خَطَٰيَٰنَآ أَن كُنَّآ أَوَّلَ ٱلْمُؤْمِنِينَ", transliteration: "Inna natmaAAu an yaghfira lana rabbuna khatayana an kunna awwala almumineena", transliterationB: "Innaa natma'u ai yaghfira lanaa Rabbunna khataa yaanaaa an kunnaaa awwalal mu'mineen", english: "Only, our desire is that our Lord will forgive us our faults, that we may become foremost among the believers", romanUrdu: "Aur humein tawaqqu hai ke hamara Rubb hamare gunaah maaf kardega kyunke sabse pehle hum iman laye hain”" },
    { number: 52, arabic: "۞ وَأَوْحَيْنَآ إِلَىٰ مُوسَىٰٓ أَنْ أَسْرِ بِعِبَادِىٓ إِنَّكُم مُّتَّبَعُونَ", transliteration: "Waawhayna ila moosa an asri biAAibadee innakum muttabaAAoona", transliterationB: "Wa awhainaaa ilaa Moosaaa an asri bi'ibaadeee innakum muttaba'oon", english: "By inspiration we told Moses: \"Travel by night with my servants; for surely ye shall be pursued", romanUrdu: "Humne Moosa ko wahee (revelation) bhejhi ke “raat o raat mere bandon ko lekar nikal jao, tumhara peecha kiya jayega”" },
    { number: 53, arabic: "فَأَرْسَلَ فِرْعَوْنُ فِى ٱلْمَدَآئِنِ حَٰشِرِينَ", transliteration: "Faarsala firAAawnu fee almadaini hashireena", transliterationB: "Fa arsala Fir'awnu filmadaaa'ini haashireen", english: "Then Pharaoh sent heralds to (all) the Cities", romanUrdu: "Ispar Firoun ne (Faujein jama karne ke liye) shehron mein naqeeb (heralds) bhej diye" },
    { number: 54, arabic: "إِنَّ هَٰٓؤُلَآءِ لَشِرْذِمَةٌۭ قَلِيلُونَ", transliteration: "Inna haolai lashirthimatun qaleeloona", transliterationB: "Inna haaa'ulaaa'i lashir zimatun qaleeloon", english: "(Saying): \"These (Israelites) are but a small band", romanUrdu: "(aur kehla bheja) ke “yeh kuch mutthi bhar log hain" },
    { number: 55, arabic: "وَإِنَّهُمْ لَنَا لَغَآئِظُونَ", transliteration: "Wainnahum lana laghaithoona", transliterationB: "Wa innahum lanaa laghaaa'izoon", english: "And they are raging furiously against us", romanUrdu: "Aur inhon ne humko bahut naraaz kiya hai" },
    { number: 56, arabic: "وَإِنَّا لَجَمِيعٌ حَٰذِرُونَ", transliteration: "Wainna lajameeAAun hathiroona", transliterationB: "Wa innaa lajamee'un haaziroon", english: "But we are a multitude amply fore-warned", romanUrdu: "Aur hum ek aisi jamaat hain jiska shewa har waqt chokanna rehna hai”" },
    { number: 57, arabic: "فَأَخْرَجْنَٰهُم مِّن جَنَّٰتٍۢ وَعُيُونٍۢ", transliteration: "Faakhrajnahum min jannatin waAAuyoonin", transliterationB: "Fa akhrajnaahum min Jannaatinw wa 'uyoon", english: "So We expelled them from gardens, springs", romanUrdu: "Is tarah hum unhein unke baaghon aur chashmon (water –springs)" },
    { number: 58, arabic: "وَكُنُوزٍۢ وَمَقَامٍۢ كَرِيمٍۢ", transliteration: "Wakunoozin wamaqamin kareemin", transliterationB: "Wa kunoozinw wa ma qaamin kareem", english: "Treasures, and every kind of honourable position", romanUrdu: "Aur khazano aur unki behtareen qayam-gaahon se nikal laaye" },
    { number: 59, arabic: "كَذَٰلِكَ وَأَوْرَثْنَٰهَا بَنِىٓ إِسْرَٰٓءِيلَ", transliteration: "Kathalika waawrathnaha banee israeela", transliterationB: "Kazaalika wa awrasnaahaa Baneee Israaa'eel", english: "Thus it was, but We made the Children of Israel inheritors of such things", romanUrdu: "Yeh to hua unke saath aur (dusri taraf) bani Israel ko humne in sab cheezon ka waris kardiya" },
    { number: 60, arabic: "فَأَتْبَعُوهُم مُّشْرِقِينَ", transliteration: "FaatbaAAoohum mushriqeena", transliterationB: "Fa atba'oohum mushriqeen", english: "So they pursued them at sunrise", romanUrdu: "Subah hotey hi yeh log unke taaqub (pursuit) mein chal paday" },
    { number: 61, arabic: "فَلَمَّا تَرَٰٓءَا ٱلْجَمْعَانِ قَالَ أَصْحَٰبُ مُوسَىٰٓ إِنَّا لَمُدْرَكُونَ", transliteration: "Falamma taraa aljamAAani qala ashabu moosa inna lamudrakoona", transliterationB: "Falammaa taraaa'al jam'aani qaala as haabu Moosaaa innaa lamudrakoon", english: "And when the two bodies saw each other, the people of Moses said: \"We are sure to be overtaken", romanUrdu: "Jab dono girohon ka aamna saamna hua to Moosa ke saathi cheekh utthey ke “ hum to pakde gaye”" },
    { number: 62, arabic: "قَالَ كَلَّآ ۖ إِنَّ مَعِىَ رَبِّى سَيَهْدِينِ", transliteration: "Qala kalla inna maAAiya rabbee sayahdeeni", transliterationB: "Qaala kallaaa inna ma'iya Rabbee sa yahdeen", english: "(Moses) said: \"By no means! my Lord is with me! Soon will He guide me", romanUrdu: "Moosa ne kaha “ hargiz nahin mere saath mera Rubb hai, woh zaroor meri rehnumayi farmayega”" },
    { number: 63, arabic: "فَأَوْحَيْنَآ إِلَىٰ مُوسَىٰٓ أَنِ ٱضْرِب بِّعَصَاكَ ٱلْبَحْرَ ۖ فَٱنفَلَقَ فَكَانَ كُلُّ فِرْقٍۢ كَٱلطَّوْدِ ٱلْعَظِيمِ", transliteration: "Faawhayna ila moosa ani idrib biAAasaka albahra fainfalaqa fakana kullu firqin kaalttawdi alAAatheemi", transliterationB: "Fa awhainaaa ilaa Moosaaa anidrib bi'asaakal bahra fanfalaqa fakaana kullu firqin kattawdil 'azeem", english: "Then We told Moses by inspiration: \"Strike the sea with thy rod.\" So it divided, and each separate part became like the huge, firm mass of a mountain", romanUrdu: "Humne Moosa ko wahee ke zariye se hukum diya ke “maar apna asa (staff) samandar par” yakayak samandar pahtt gaya aur uska har tukda ek azeem o shaan pahad ki tarah ho gaya" },
    { number: 64, arabic: "وَأَزْلَفْنَا ثَمَّ ٱلْءَاخَرِينَ", transliteration: "Waazlafna thamma alakhareena", transliterationB: "Wa azlafnaa sammal aakhareen", english: "And We made the other party approach thither", romanUrdu: "Usi jagah hum dusre giroh ko bhi kareeb le aaye" },
    { number: 65, arabic: "وَأَنجَيْنَا مُوسَىٰ وَمَن مَّعَهُۥٓ أَجْمَعِينَ", transliteration: "Waanjayna moosa waman maAAahu ajmaAAeena", transliterationB: "Wa anjainaa Moosaa wa mam ma'ahooo ajma'een", english: "We delivered Moses and all who were with him", romanUrdu: "Moosa aur un sab logon ko jo uske saath thay humne bacha liya" },
    { number: 66, arabic: "ثُمَّ أَغْرَقْنَا ٱلْءَاخَرِينَ", transliteration: "Thumma aghraqna alakhareena", transliterationB: "Summa aghraqnal aakhareen", english: "But We drowned the others", romanUrdu: "Aur dusron ko garq (duba/drown) kardiya" },
    { number: 67, arabic: "إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ", transliteration: "Inna fee thalika laayatan wama kana aktharuhum mumineena", transliterationB: "Inna fee zaalika la Aayaah; wa maa kaana aksaru hu mu'mineen", english: "Verily in this is a Sign: but most of them do not believe", romanUrdu: "Is waqiye mein ek nishani hai, magar in logon mein se aksar manney waley nahin hain" },
    { number: 68, arabic: "وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ", transliteration: "Wainna rabbaka lahuwa alAAazeezu alrraheemu", transliterationB: "Wa inna Rabbaka la Huwal 'Azeezur Raheem", english: "And verily thy Lord is He, the Exalted in Might, Most Merciful", romanUrdu: "Aur haqeeqat yeh hai ke tera Rubb zabardast bhi hai aur raheem bhi" },
    { number: 69, arabic: "وَٱتْلُ عَلَيْهِمْ نَبَأَ إِبْرَٰهِيمَ", transliteration: "Waotlu AAalayhim nabaa ibraheema", transliterationB: "Watlu 'alaihim naba-a Ibraaheem", english: "And rehearse to them (something of) Abraham's story", romanUrdu: "Aur inhein Ibrahim ka qissa sunao" },
    { number: 70, arabic: "إِذْ قَالَ لِأَبِيهِ وَقَوْمِهِۦ مَا تَعْبُدُونَ", transliteration: "Ith qala liabeehi waqawmihi ma taAAbudoona", transliterationB: "Iz qaala li abeehi wa qawmihee maa ta'budoon", english: "Behold, he said to his father and his people: \"What worship ye", romanUrdu: "Jabke usne apne baap aur apni qaum se pucha tha ke “yeh kya cheezein hain jinko tum poojhte ho?”" },
    { number: 71, arabic: "قَالُوا۟ نَعْبُدُ أَصْنَامًۭا فَنَظَلُّ لَهَا عَٰكِفِينَ", transliteration: "Qaloo naAAbudu asnaman fanathallu laha AAakifeena", transliterationB: "Qaaloo na'budu asnaaman fanazallu lahaa 'aakifeen", english: "They said: \"We worship idols, and we remain constantly in attendance on them", romanUrdu: "Unhon ne jawab diya “ kuch buth (idols/murtiyan) hain jinki hum pooja karte hain aur inhi ki sewa mein hum lagey rehte hain”" },
    { number: 72, arabic: "قَالَ هَلْ يَسْمَعُونَكُمْ إِذْ تَدْعُونَ", transliteration: "Qala hal yasmaAAoonakum ith tadAAoona", transliterationB: "Qaala hal yasma'oona kum iz tad'oon", english: "He said: \"Do they listen to you when ye call (on them)", romanUrdu: "Usne pucha “kya yeh tumhari sunte hain jab tum inhein pukarte ho" },
    { number: 73, arabic: "أَوْ يَنفَعُونَكُمْ أَوْ يَضُرُّونَ", transliteration: "Aw yanfaAAoonakum aw yadurroona", transliterationB: "Aw yanfa'oonakum aw yadurroon", english: "Or do you good or harm", romanUrdu: "Ya yeh tumhein kuch nafaa ya nuqsaan pahunchate hain?”" },
    { number: 74, arabic: "قَالُوا۟ بَلْ وَجَدْنَآ ءَابَآءَنَا كَذَٰلِكَ يَفْعَلُونَ", transliteration: "Qaloo bal wajadna abaana kathalika yafAAaloona", transliterationB: "Qaaloo bal wajadnaaa aabaaa 'anaa kazaalika yaf'aloon", english: "They said: \"Nay, but we found our fathers doing thus (what we do)", romanUrdu: "Unhon ne jawab diya “ nahin , balke humne apne baap dada ko aisa hi karte paya hai”" },
    { number: 75, arabic: "قَالَ أَفَرَءَيْتُم مَّا كُنتُمْ تَعْبُدُونَ", transliteration: "Qala afaraaytum ma kuntum taAAbudoona", transliterationB: "Qaala afara 'aitum maa kuntum ta'budoon", english: "He said: \"Do ye then see whom ye have been worshipping", romanUrdu: "Ispar Ibrahim ne kaha “ kabhi tumne (aankhein khol kar) un cheezon ko dekha bhi jinki bandagi tum" },
    { number: 76, arabic: "أَنتُمْ وَءَابَآؤُكُمُ ٱلْأَقْدَمُونَ", transliteration: "Antum waabaokumu alaqdamoona", transliterationB: "Antum wa aabaaa'ukumul aqdamoon", english: "Ye and your fathers before you", romanUrdu: "Aur tumhare pichle baap dada baja latey rahey" },
    { number: 77, arabic: "فَإِنَّهُمْ عَدُوٌّۭ لِّىٓ إِلَّا رَبَّ ٱلْعَٰلَمِينَ", transliteration: "Fainnahum AAaduwwun lee illa rabba alAAalameena", transliterationB: "Fa innahum 'aduwwwul leee illaa Rabbal 'aalameen", english: "For they are enemies to me; not so the Lord and Cherisher of the Worlds", romanUrdu: "Mere to yeh sab dushman hain, bajuz ek Rubb ul aalameen ke" },
    { number: 78, arabic: "ٱلَّذِى خَلَقَنِى فَهُوَ يَهْدِينِ", transliteration: "Allathee khalaqanee fahuwa yahdeeni", transliterationB: "Allazee khalaqanee fa Huwa yahdeen", english: "Who created me, and it is He Who guides me", romanUrdu: "Jisne mujhey paida kiya, phir wahi meri rehnumayi farmata hai" },
    { number: 79, arabic: "وَٱلَّذِى هُوَ يُطْعِمُنِى وَيَسْقِينِ", transliteration: "Waallathee huwa yutAAimunee wayasqeeni", transliterationB: "Wallazee Huwa yut'imunee wa yasqeen", english: "Who gives me food and drink", romanUrdu: "Jo mujhey khilata aur pilata hai" },
    { number: 80, arabic: "وَإِذَا مَرِضْتُ فَهُوَ يَشْفِينِ", transliteration: "Waitha maridtu fahuwa yashfeeni", transliterationB: "Wa izaa mardtu fahuwa yashfeen", english: "And when I am ill, it is He Who cures me", romanUrdu: "Aur jab main bimar ho jaata hoon to wahi mujhey shifa deta hai" },
    { number: 81, arabic: "وَٱلَّذِى يُمِيتُنِى ثُمَّ يُحْيِينِ", transliteration: "Waallathee yumeetunee thumma yuhyeeni", transliterationB: "Wallazee yumeetunee summa yuhyeen", english: "Who will cause me to die, and then to life (again)", romanUrdu: "Jo mujhey maut dega aur phir dobara mujhko zindagi bakshega" },
    { number: 82, arabic: "وَٱلَّذِىٓ أَطْمَعُ أَن يَغْفِرَ لِى خَطِيٓـَٔتِى يَوْمَ ٱلدِّينِ", transliteration: "Waallathee atmaAAu an yaghfira lee khateeatee yawma alddeeni", transliterationB: "Wallazeee atma'u ai yaghfira lee khateee' atee Yawmad Deen", english: "And who, I hope, will forgive me my faults on the day of Judgment", romanUrdu: "Aur jissey main umeed rakhta hoon ke roz e jaza mein woh meri khata maaf farmadega”" },
    { number: 83, arabic: "رَبِّ هَبْ لِى حُكْمًۭا وَأَلْحِقْنِى بِٱلصَّٰلِحِينَ", transliteration: "Rabbi hab lee hukman waalhiqnee bialssaliheena", transliterationB: "Rabbi hab lee hukmanw wa alhiqnee bis saaliheen", english: "O my Lord! bestow wisdom on me, and join me with the righteous", romanUrdu: "(iske baad Ibrahim ne dua ki) “Aey mere Rubb, mujhey hukum ata kar aur mujhko salihon (neik logon) ke saath mila" },
    { number: 84, arabic: "وَٱجْعَل لِّى لِسَانَ صِدْقٍۢ فِى ٱلْءَاخِرِينَ", transliteration: "WaijAAal lee lisana sidqin fee alakhireena", transliterationB: "Waj'al lee lisaana sidqin fil aakhireen", english: "Grant me honourable mention on the tongue of truth among the latest (generations)", romanUrdu: "Aur baad ke aane walon mein mujhko sacchi naamwari ata kar" },
    { number: 85, arabic: "وَٱجْعَلْنِى مِن وَرَثَةِ جَنَّةِ ٱلنَّعِيمِ", transliteration: "WaijAAalnee min warathati jannati alnnaAAeemi", transliterationB: "Waj'alnee minw warasati Jannnatin Na'eem", english: "Make me one of the inheritors of the Garden of Bliss", romanUrdu: "Aur mujhey jannat e naeem ke warison (inheritors) mein shamil farma" },
    { number: 86, arabic: "وَٱغْفِرْ لِأَبِىٓ إِنَّهُۥ كَانَ مِنَ ٱلضَّآلِّينَ", transliteration: "Waighfir liabee innahu kana mina alddalleena", transliterationB: "Waghfir li abeee innahoo kaana mind daalleen", english: "Forgive my father, for that he is among those astray", romanUrdu: "Aur mere baap ko maaf karde ke beshak woh gumraah logon mein se hai" },
    { number: 87, arabic: "وَلَا تُخْزِنِى يَوْمَ يُبْعَثُونَ", transliteration: "Wala tukhzinee yawma yubAAathoona", transliterationB: "Wa laa tukhzinee Yawma yub'asoon", english: "And let me not be in disgrace on the Day when (men) will be raised up", romanUrdu: "Aur mujhey us din ruswa na kar jabke sab log zinda karke uthaye jayenge" },
    { number: 88, arabic: "يَوْمَ لَا يَنفَعُ مَالٌۭ وَلَا بَنُونَ", transliteration: "Yawma la yanfaAAu malun wala banoona", transliterationB: "Yawma laa yanfa'u maalunw wa laa banoon", english: "The Day whereon neither wealth nor sons will avail", romanUrdu: "Jabke na maal koi faiyda dega na Aulad" },
    { number: 89, arabic: "إِلَّا مَنْ أَتَى ٱللَّهَ بِقَلْبٍۢ سَلِيمٍۢ", transliteration: "Illa man ata Allaha biqalbin saleemin", transliterationB: "Illaa man atal laaha biqalbin saleem", english: "But only he (will prosper) that brings to Allah a sound heart", romanUrdu: "Bajuz iske ke koi shaks qalb-e-saleem (sound heart) liye huey Allah ke huzur haazir ho”" },
    { number: 90, arabic: "وَأُزْلِفَتِ ٱلْجَنَّةُ لِلْمُتَّقِينَ", transliteration: "Waozlifati aljannatu lilmuttaqeena", transliterationB: "Wa uzlifatil Jannatu lilmuttaqeen", english: "To the righteous, the Garden will be brought near", romanUrdu: "(Us roz) jannat parheizgaaron ke qareeb le aayi jayegi" },
    { number: 91, arabic: "وَبُرِّزَتِ ٱلْجَحِيمُ لِلْغَاوِينَ", transliteration: "Waburrizati aljaheemu lilghaweena", transliterationB: "Wa burrizatil Jaheemu lilghaaween", english: "And to those straying in Evil, the Fire will be placed in full view", romanUrdu: "Aur dozakh behke huey logon ke saamne khol di jayegi" },
    { number: 92, arabic: "وَقِيلَ لَهُمْ أَيْنَ مَا كُنتُمْ تَعْبُدُونَ", transliteration: "Waqeela lahum ayna ma kuntum taAAbudoona", transliterationB: "Wa qeela lahum aina maa kuntum ta'budoon", english: "And it shall be said to them: 'Where are the (gods) ye worshipped", romanUrdu: "Aur unsey pucha jayega ke “ab kahan hai woh jinki tum khuda ko chodh kar ibadat karte thay" },
    { number: 93, arabic: "مِن دُونِ ٱللَّهِ هَلْ يَنصُرُونَكُمْ أَوْ يَنتَصِرُونَ", transliteration: "Min dooni Allahi hal yansuroonakum aw yantasiroona", transliterationB: "Min doonil laahi hal yansuroonakum aw yantasiroon", english: "Besides Allah? Can they help you or help themselves", romanUrdu: "Kya woh tumhari kuch madad kar rahey hain ya khud apna bachao kar sakte hain?”" },
    { number: 94, arabic: "فَكُبْكِبُوا۟ فِيهَا هُمْ وَٱلْغَاوُۥنَ", transliteration: "Fakubkiboo feeha hum waalghawoona", transliterationB: "Fakubkiboo feehaa hum walghaawoon", english: "Then they will be thrown headlong into the (Fire),- they and those straying in Evil", romanUrdu: "Phir woh mabood aur yeh behke huey log" },
    { number: 95, arabic: "وَجُنُودُ إِبْلِيسَ أَجْمَعُونَ", transliteration: "Wajunoodu ibleesa ajmaAAoona", transliterationB: "Wa junoodu Ibleesa ajma'oon", english: "And the whole hosts of Iblis together", romanUrdu: "Aur Iblis ke lashkar sabke sab ismein upar taley dhakeil diye jayenge" },
    { number: 96, arabic: "قَالُوا۟ وَهُمْ فِيهَا يَخْتَصِمُونَ", transliteration: "Qaloo wahum feeha yakhtasimoona", transliterationB: "Qaaloo wa hum feehaa yakkhtasimoon", english: "They will say there in their mutual bickerings", romanUrdu: "Wahan yeh sab aapas mein jhagdenge aur yeh behke huey log (apne maboodon se) kahenge" },
    { number: 97, arabic: "تَٱللَّهِ إِن كُنَّا لَفِى ضَلَٰلٍۢ مُّبِينٍ", transliteration: "TaAllahi in kunna lafee dalalin mubeenin", transliterationB: "Tallaahi in kunnaa lafee dalaalim mubeen", english: "By Allah, we were truly in an error manifest", romanUrdu: "Ke “khuda ki kasam , hum to sareeh gumraahi mein mubtala thay" },
    { number: 98, arabic: "إِذْ نُسَوِّيكُم بِرَبِّ ٱلْعَٰلَمِينَ", transliteration: "Ith nusawweekum birabbi alAAalameena", transliterationB: "Iz nusawweekum bi Rabbil 'aalameen", english: "When we held you as equals with the Lord of the Worlds", romanUrdu: "Jabke tumko Rubb ul Aalameen ki barabari ka darja de rahey thay" },
    { number: 99, arabic: "وَمَآ أَضَلَّنَآ إِلَّا ٱلْمُجْرِمُونَ", transliteration: "Wama adallana illa almujrimoona", transliterationB: "Wa maaa adallanaaa illal mujrimoon", english: "And our seducers were only those who were steeped in guilt", romanUrdu: "Aur woh mujrim log hi thay jinhon ne humko is gumraahi mein dala" },
    { number: 100, arabic: "فَمَا لَنَا مِن شَٰفِعِينَ", transliteration: "Fama lana min shafiAAeena", transliterationB: "Famaa lanaa min shaa fi'een", english: "Now, then, we have none to intercede (for us)", romanUrdu: "Ab na hamara koi sifarishi hai" },
    { number: 101, arabic: "وَلَا صَدِيقٍ حَمِيمٍۢ", transliteration: "Wala sadeeqin hameemin", transliterationB: "Wa laa sadeeqin hameem", english: "Nor a single friend to feel (for us)", romanUrdu: "Aur na koi jigri dost" },
    { number: 102, arabic: "فَلَوْ أَنَّ لَنَا كَرَّةًۭ فَنَكُونَ مِنَ ٱلْمُؤْمِنِينَ", transliteration: "Falaw anna lana karratan fanakoona mina almumineena", transliterationB: "Falaw anna lanaa karratan fanakoona minal mu'mineen", english: "Now if we only had a chance of return we shall truly be of those who believe", romanUrdu: "Kaash humein ek dafa phir palatne ka mauqa mil jaye to hum momin hon”" },
    { number: 103, arabic: "إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ", transliteration: "Inna fee thalika laayatan wama kana aktharuhum mumineena", transliterationB: "Inna fee zaalika la Aayatanw wa maa kaana aksaruhum mu'mineen", english: "Verily in this is a Sign but most of them do not believe", romanUrdu: "Yaqeenan is mein ek badi nishani hai, magar in mein se aksar log iman laney waley nahin" },
    { number: 104, arabic: "وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ", transliteration: "Wainna rabbaka lahuwa alAAazeezu alrraheemu", transliterationB: "Wa inna Rabbaka la Huwal 'Azeezur Raheem", english: "And verily thy Lord is He, the Exalted in Might, Most Merciful", romanUrdu: "Aur haqeeqat yeh hai ke tera Rubb zabardast bhi hai aur raheem bhi" },
    { number: 105, arabic: "كَذَّبَتْ قَوْمُ نُوحٍ ٱلْمُرْسَلِينَ", transliteration: "Kaththabat qawmu noohin almursaleena", transliterationB: "Kazzabat qawmu Noohinil Mursaleen", english: "The people of Noah rejected the messengers", romanUrdu: "Qaum e Nooh ne Rasoolon ko jhutlaya" },
    { number: 106, arabic: "إِذْ قَالَ لَهُمْ أَخُوهُمْ نُوحٌ أَلَا تَتَّقُونَ", transliteration: "Ith qala lahum akhoohum noohun ala tattaqoona", transliterationB: "Iz qaala lahum akhoohum Noohun alaa tattaqoon", english: "Behold, their brother Noah said to them: \"Will ye not fear (Allah)", romanUrdu: "Yaad karo jabke unke bhai Nooh ne unsey kaha tha “kya tum darte nahin ho" },
    { number: 107, arabic: "إِنِّى لَكُمْ رَسُولٌ أَمِينٌۭ", transliteration: "Innee lakum rasoolun ameenun", transliterationB: "Innee lakum Rasoolun ameen", english: "I am to you a messenger worthy of all trust", romanUrdu: "Main tumhare liye ek amaanat daar Rasool hoon" },
    { number: 108, arabic: "فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ", transliteration: "Faittaqoo Allaha waateeAAooni", transliterationB: "Fattaqullaaha wa atee'oon", english: "So fear Allah, and obey me", romanUrdu: "Lihaza tum Allah se daro aur meri itaat karo" },
    { number: 109, arabic: "وَمَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنْ أَجْرٍ ۖ إِنْ أَجْرِىَ إِلَّا عَلَىٰ رَبِّ ٱلْعَٰلَمِينَ", transliteration: "Wama asalukum AAalayhi min ajrin in ajriya illa AAala rabbi alAAalameena", transliterationB: "Wa maaa as'alukum 'alaihi min ajrin in ajriya illaa 'alaa Rabbil 'aalameen", english: "No reward do I ask of you for it: my reward is only from the Lord of the Worlds", romanUrdu: "Main is kaam par tumse kisi ajar ka talib nahin hoon, mera ajar to Rabbul Aalameen ke zimme hai" },
    { number: 110, arabic: "فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ", transliteration: "Faittaqoo Allaha waateeAAooni", transliterationB: "Fattaqul laaha wa atee'oon", english: "So fear Allah, and obey me", romanUrdu: "Pas tum Allah se daro aur ( be khatke) meri itaat karo”" },
    { number: 111, arabic: "۞ قَالُوٓا۟ أَنُؤْمِنُ لَكَ وَٱتَّبَعَكَ ٱلْأَرْذَلُونَ", transliteration: "Qaloo anuminu laka waittabaAAaka alarthaloona", transliterationB: "Qaalooo anu'minu laka wattaba 'akal arzaloon", english: "They said: \"Shall we believe in thee when it is the meanest that follow thee", romanUrdu: "Unhon ne jawab diya “kya hum tujhey maan lein halaanke teri pairwi razil-tareen (lowest/meanest) logon ne ikhtiyar ki hai?”" },
    { number: 112, arabic: "قَالَ وَمَا عِلْمِى بِمَا كَانُوا۟ يَعْمَلُونَ", transliteration: "Qala wama AAilmee bima kanoo yaAAmaloona", transliterationB: "Qaala wa maa 'ilmee bimaa kaanoo ya'maloon", english: "He said: \"And what do I know as to what they do", romanUrdu: "Nooh ne kaha “main kya jaanu ke unke amal kaise hain" },
    { number: 113, arabic: "إِنْ حِسَابُهُمْ إِلَّا عَلَىٰ رَبِّى ۖ لَوْ تَشْعُرُونَ", transliteration: "In hisabuhum illa AAala rabbee law tashAAuroona", transliterationB: "In hisaabuhum illaa 'alaa Rabbee law tash'uroon", english: "Their account is only with my Lord, if ye could (but) understand", romanUrdu: "Unka hisaab to mere Rubb ke zimme hai, kaash tum kuch shaoor se kaam lo" },
    { number: 114, arabic: "وَمَآ أَنَا۠ بِطَارِدِ ٱلْمُؤْمِنِينَ", transliteration: "Wama ana bitaridi almumineena", transliterationB: "Wa maaa ana bitaaridil mu'mineen", english: "I am not one to drive away those who believe", romanUrdu: "Mera yeh kaam nahin hai ke jo iman layein unko main dhutkaar doon" },
    { number: 115, arabic: "إِنْ أَنَا۠ إِلَّا نَذِيرٌۭ مُّبِينٌۭ", transliteration: "In ana illa natheerun mubeenun", transliterationB: "In ana illaa nazeerum mubeen", english: "I am sent only to warn plainly in public", romanUrdu: "Main to bas ek saaf saaf mutanabbeh (warn) kardene wala aadmi hoon”" },
    { number: 116, arabic: "قَالُوا۟ لَئِن لَّمْ تَنتَهِ يَٰنُوحُ لَتَكُونَنَّ مِنَ ٱلْمَرْجُومِينَ", transliteration: "Qaloo lain lam tantahi ya noohu latakoonanna mina almarjoomeena", transliterationB: "Qaaloo la'il lam tantahi yaa Noohu latakoonanna minal marjoomeen", english: "They said: \"If thou desist not, O Noah! thou shalt be stoned (to death)", romanUrdu: "Unhon ne kaha “Aey Nooh , agar tu baaz na aaya to phitkarey huey logon mein shamil hokar rahega”" },
    { number: 117, arabic: "قَالَ رَبِّ إِنَّ قَوْمِى كَذَّبُونِ", transliteration: "Qala rabbi inna qawmee kaththabooni", transliterationB: "Qaala Rabbi inna qawmee kazzaboon", english: "He said: \"O my Lord! truly my people have rejected me", romanUrdu: "Nooh ne dua ki “Aey mere Rubb, meri qaum ne mujhey jhutla diya" },
    { number: 118, arabic: "فَٱفْتَحْ بَيْنِى وَبَيْنَهُمْ فَتْحًۭا وَنَجِّنِى وَمَن مَّعِىَ مِنَ ٱلْمُؤْمِنِينَ", transliteration: "Faiftah baynee wabaynahum fathan wanajjinee waman maAAiya mina almumineena", transliterationB: "Faftab bainee wa bai nahum fat hanw wa najjinee wa mam ma'iya minal mu'mineen", english: "Judge Thou, then, between me and them openly, and deliver me and those of the Believers who are with me", romanUrdu: "Ab mere aur unke darmiyan do-toak faisla karde aur mujhey aur jo momin mere saath hain inko nijaat de”" },
    { number: 119, arabic: "فَأَنجَيْنَٰهُ وَمَن مَّعَهُۥ فِى ٱلْفُلْكِ ٱلْمَشْحُونِ", transliteration: "Faanjaynahu waman maAAahu fee alfulki almashhooni", transliterationB: "Fa anjainaahu wa mamma'ahoo fil fulkil mashhoon", english: "So We delivered him and those with him, in the Ark filled (with all creatures)", romanUrdu: "Aakhir e kaar humne usko aur uske saathiyon ko ek bhaari hui kashti mein bacha liya" },
    { number: 120, arabic: "ثُمَّ أَغْرَقْنَا بَعْدُ ٱلْبَاقِينَ", transliteration: "Thumma aghraqna baAAdu albaqeena", transliterationB: "Summa aghraqnaa ba'dul baaqeen", english: "Thereafter We drowned those who remained behind", romanUrdu: "Aur uske baad baaqi logon ko garq (drown) kardiya" },
    { number: 121, arabic: "إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ", transliteration: "Inna fee thalika laayatan wama kana aktharuhum mumineena", transliterationB: "Inna fee zaalika la Aayaah; wa maa kaana aksaruhum mu'mineen", english: "Verily in this is a Sign: but most of them do not believe", romanUrdu: "Yaqeenan ismein ek nishani hai, magar inmein se aksar log maanne waley nahin" },
    { number: 122, arabic: "وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ", transliteration: "Wainna rabbaka lahuwa alAAazeezu alrraheemu", transliterationB: "Wa inna Rabbaka la huwal 'Azeezur Raheem", english: "And verily thy Lord is He, the Exalted in Might, Most Merciful", romanUrdu: "Aur haqeeqat yeh hai ke tera Rubb zabardast bhi hai aur raheem bhi" },
    { number: 123, arabic: "كَذَّبَتْ عَادٌ ٱلْمُرْسَلِينَ", transliteration: "Kaththabat AAadun almursaleena", transliterationB: "Kazzabat 'Aadunil mursaleen", english: "The 'Ad (people) rejected the messengers", romanUrdu: "Aad ne Rasoolon ko jhutlaya" },
    { number: 124, arabic: "إِذْ قَالَ لَهُمْ أَخُوهُمْ هُودٌ أَلَا تَتَّقُونَ", transliteration: "Ith qala lahum akhoohum hoodun ala tattaqoona", transliterationB: "Iz qaala lahum akhoohum Hoodun alaa tattaqoon", english: "Behold, their brother Hud said to them: \"Will ye not fear (Allah)", romanUrdu: "Yaad karo jabke unke bhai Hood ne unse kaha tha “kya tum darte nahin" },
    { number: 125, arabic: "إِنِّى لَكُمْ رَسُولٌ أَمِينٌۭ", transliteration: "Innee lakum rasoolun ameenun", transliterationB: "Innee lakum Rasoolun ameen", english: "I am to you a messenger worthy of all trust", romanUrdu: "Main tumhare liye ek amaanat-daar Rasool hoon" },
    { number: 126, arabic: "فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ", transliteration: "Faittaqoo Allaha waateeAAooni", transliterationB: "Fattaqullaaha wa atee'oon", english: "So fear Allah and obey me", romanUrdu: "Lihaza tum Allah se daro aur meri itaat karo" },
    { number: 127, arabic: "وَمَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنْ أَجْرٍ ۖ إِنْ أَجْرِىَ إِلَّا عَلَىٰ رَبِّ ٱلْعَٰلَمِينَ", transliteration: "Wama asalukum AAalayhi min ajrin in ajriya illa AAala rabbi alAAalameena", transliterationB: "Wa maa as'alukum 'alaihi min ajrin in ajriya illaa 'alaa Rabbil 'aalameen", english: "No reward do I ask of you for it: my reward is only from the Lord of the Worlds", romanUrdu: "Main is kaam par tumse kisi ajar ka talib nahin hoon, mera ajar to Rabbul Aalameen ke zimme hai" },
    { number: 128, arabic: "أَتَبْنُونَ بِكُلِّ رِيعٍ ءَايَةًۭ تَعْبَثُونَ", transliteration: "Atabnoona bikulli reeAAin ayatan taAAbathoona", transliterationB: "Atabnoona bikulli ree'in aayatan ta'basoon", english: "Do ye build a landmark on every high place to amuse yourselves", romanUrdu: "Yeh tumhara kya haal hai ke har unchey maqaam par la haasil ek yaadgaar imarat bana daalte ho" },
    { number: 129, arabic: "وَتَتَّخِذُونَ مَصَانِعَ لَعَلَّكُمْ تَخْلُدُونَ", transliteration: "Watattakhithoona masaniAAa laAAallakum takhludoona", transliterationB: "Wa tattakhizoona masaani'a la'allakum takhludoon", english: "And do ye get for yourselves fine buildings in the hope of living therein (for ever)", romanUrdu: "Aur baday baday qasar (huge castles) taamir karte ho goya tumhein hamesha rehna hai" },
    { number: 130, arabic: "وَإِذَا بَطَشْتُم بَطَشْتُمْ جَبَّارِينَ", transliteration: "Waitha batashtum batashtum jabbareena", transliterationB: "Wa izaa batashtum batashtum jabbaareen", english: "And when ye exert your strong hand, do ye do it like men of absolute power", romanUrdu: "Aur jab kisi par haath daalte ho jabbar ban kar daalte ho" },
    { number: 131, arabic: "فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ", transliteration: "Faittaqoo Allaha waateeAAooni", transliterationB: "Fattaqul laaha wa atee'oon", english: "Now fear Allah, and obey me", romanUrdu: "Pas tum log Allah se daro aur meri itaat karo" },
    { number: 132, arabic: "وَٱتَّقُوا۟ ٱلَّذِىٓ أَمَدَّكُم بِمَا تَعْلَمُونَ", transliteration: "Waittaqoo allathee amaddakum bima taAAlamoona", transliterationB: "Wattaqul lazeee amad dakum bimaa ta'lamoon", english: "Yea, fear Him Who has bestowed on you freely all that ye know", romanUrdu: "Daro ussey jisne woh kuch tumhein diya hai jo tum jaante ho" },
    { number: 133, arabic: "أَمَدَّكُم بِأَنْعَٰمٍۢ وَبَنِينَ", transliteration: "Amaddakum bianAAamin wabaneena", transliterationB: "Amaddakum bi an'aa minw wa baneen", english: "Freely has He bestowed on you cattle and sons", romanUrdu: "Tumhein jaanwar diye, auladein di" },
    { number: 134, arabic: "وَجَنَّٰتٍۢ وَعُيُونٍ", transliteration: "Wajannatin waAAuyoonin", transliterationB: "Wa jannaatinw wa 'uyoon", english: "And Gardens and Springs", romanUrdu: "Baagh diye aur chashme(water-springs) diye" },
    { number: 135, arabic: "إِنِّىٓ أَخَافُ عَلَيْكُمْ عَذَابَ يَوْمٍ عَظِيمٍۢ", transliteration: "Innee akhafu AAalaykum AAathaba yawmin AAatheemin", transliterationB: "Innee akhaafu 'alaikum 'azaaba Yawmin 'azeem", english: "Truly I fear for you the Penalty of a Great Day", romanUrdu: "Mujhey tumhare haqq mein ek baday din ke azaab ka darr hai”" },
    { number: 136, arabic: "قَالُوا۟ سَوَآءٌ عَلَيْنَآ أَوَعَظْتَ أَمْ لَمْ تَكُن مِّنَ ٱلْوَٰعِظِينَ", transliteration: "Qaloo sawaon AAalayna awaAAathta am lam takun mina alwaAAitheena", transliterationB: "Qaaloo sawaaa'un 'alainaaa awa 'azta am lam takum minal waa'izeen", english: "They said: \"It is the same to us whether thou admonish us or be not among (our) admonishers", romanUrdu: "Unhon ne jawaab diya “ tu naseehat kar ya na kar, hamare liye yaksan hai" },
    { number: 137, arabic: "إِنْ هَٰذَآ إِلَّا خُلُقُ ٱلْأَوَّلِينَ", transliteration: "In hatha illa khuluqu alawwaleena", transliterationB: "In haazaaa illaa khuluqul awwaleen", english: "This is no other than a customary device of the ancients", romanUrdu: "Yeh baatein to yunhi hoti chali aayi hain" },
    { number: 138, arabic: "وَمَا نَحْنُ بِمُعَذَّبِينَ", transliteration: "Wama nahnu bimuAAaththabeena", transliterationB: "Wa maa nahnu bimu 'azzabeen", english: "And we are not the ones to receive Pains and Penalties", romanUrdu: "Aur hum azaab mein mubtala honay walay nahin hain”" },
    { number: 139, arabic: "فَكَذَّبُوهُ فَأَهْلَكْنَٰهُمْ ۗ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ", transliteration: "Fakaththaboohu faahlaknahum inna fee thalika laayatan wama kana aktharuhum mumineena", transliterationB: "Fakazzaboohu fa ahlaknaahum; inna fee zaalika la aayah; wa maa kaana aksaruhum mu'mineen", english: "So they rejected him, and We destroyed them. Verily in this is a Sign: but most of them do not believe", romanUrdu: "Aakhir e kaar unhon ne usey jhutla diya aur humne unko halaak kardiya. Yaqeenan ismein ek nishani hai, magar inmein se aksar log maanne waley nahin hai" },
    { number: 140, arabic: "وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ", transliteration: "Wainna rabbaka lahuwa alAAazeezu alrraheemu", transliterationB: "Wa inna Rabbaka la huwal 'Azeezur Raheem", english: "And verily thy Lord is He, the Exalted in Might, Most Merciful", romanUrdu: "Aur haqeeqat yeh hai ke tera Rubb zabardast bhi hai aur raheem bhi" },
    { number: 141, arabic: "كَذَّبَتْ ثَمُودُ ٱلْمُرْسَلِينَ", transliteration: "Kaththabat thamoodu almursaleena", transliterationB: "Kazzabat Samoodul mursaleen", english: "The Thamud (people) rejected the messengers", romanUrdu: "Samood ne Rasoolon ko jhutlaya" },
    { number: 142, arabic: "إِذْ قَالَ لَهُمْ أَخُوهُمْ صَٰلِحٌ أَلَا تَتَّقُونَ", transliteration: "Ith qala lahum akhoohum salihun ala tattaqoona", transliterationB: "Iz qaala lahum akhoohum Saalihun alaa tattaqoon", english: "Behold, their brother Salih said to them: \"Will you not fear (Allah)", romanUrdu: "Yaad karo jabke unke bhai Saleh ne unse kaha “kya tum darte nahin" },
    { number: 143, arabic: "إِنِّى لَكُمْ رَسُولٌ أَمِينٌۭ", transliteration: "Innee lakum rasoolun ameenun", transliterationB: "Innee lakum Rasoolun ameen", english: "I am to you a messenger worthy of all trust", romanUrdu: "Main tumhare liye ek amaanat-daar Rasool hoon" },
    { number: 144, arabic: "فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ", transliteration: "Faittaqoo Allaha waateeAAooni", transliterationB: "Fattaqul laaha wa atee'oon", english: "So fear Allah, and obey me", romanUrdu: "Lihaza tum Allah se daro aur meri itaat karo" },
    { number: 145, arabic: "وَمَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنْ أَجْرٍ ۖ إِنْ أَجْرِىَ إِلَّا عَلَىٰ رَبِّ ٱلْعَٰلَمِينَ", transliteration: "Wama asalukum AAalayhi min ajrin in ajriya illa AAala rabbi alAAalameena", transliterationB: "Wa maaa as'alukum 'alaihi min ajrin in ajriya illaa 'alaa Rabbil 'aalameen", english: "No reward do I ask of you for it: my reward is only from the Lord of the Worlds", romanUrdu: "Main is kaam par tumse kisi ajar ka talib nahin hoon, mera ajar to Rabbul aalameen ke zimme hai" },
    { number: 146, arabic: "أَتُتْرَكُونَ فِى مَا هَٰهُنَآ ءَامِنِينَ", transliteration: "Atutrakoona fee ma hahuna amineena", transliterationB: "Atutrakoona fee maa haahunnaaa aamineen", english: "Will ye be left secure, in (the enjoyment of) all that ye have here", romanUrdu: "Kya tum un sab cheezon ke darmiyan, jo yahan hain, bas yunhi itminaan se rehne diye jaogey" },
    { number: 147, arabic: "فِى جَنَّٰتٍۢ وَعُيُونٍۢ", transliteration: "Fee jannatin waAAuyoonin", transliterationB: "Fee jannaatinw wa 'uyoon", english: "Gardens and Springs", romanUrdu: "In baaghon (gardens) aur chasmon mein" },
    { number: 148, arabic: "وَزُرُوعٍۢ وَنَخْلٍۢ طَلْعُهَا هَضِيمٌۭ", transliteration: "WazurooAAin wanakhlin talAAuha hadeemun", transliterationB: "Wa zuroo inw wa nakhlin tal 'uhaa hadeem", english: "And corn-fields and date-palms with spathes near breaking (with the weight of fruit)", romanUrdu: "In kheton aur nakhlistano (date-groves) mein jinke khosey rass bharey hain" },
    { number: 149, arabic: "وَتَنْحِتُونَ مِنَ ٱلْجِبَالِ بُيُوتًۭا فَٰرِهِينَ", transliteration: "Watanhitoona mina aljibali buyootan fariheena", transliterationB: "Wa tanhitoona minal jibaali buyootan faariheen", english: "And ye carve houses out of (rocky) mountains with great skill", romanUrdu: "Tum pahad khodh khodh kar fakhariya (proudly) un mein imaratein banate ho" },
    { number: 150, arabic: "فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ", transliteration: "Faittaqoo Allaha waateeAAooni", transliterationB: "Fattaqul laaha wa atee'oon", english: "But fear Allah and obey me", romanUrdu: "Allah se daro aur meri itaat karo" },
    { number: 151, arabic: "وَلَا تُطِيعُوٓا۟ أَمْرَ ٱلْمُسْرِفِينَ", transliteration: "Wala tuteeAAoo amra almusrifeena", transliterationB: "Wa laa tutee'ooo amral musrifeen", english: "And follow not the bidding of those who are extravagant", romanUrdu: "Un bay-lagaam logon ki itaat na karo" },
    { number: 152, arabic: "ٱلَّذِينَ يُفْسِدُونَ فِى ٱلْأَرْضِ وَلَا يُصْلِحُونَ", transliteration: "Allatheena yufsidoona fee alardi wala yuslihoona", transliterationB: "Allazeena yufsidoona fil ardi wa laa yuslihoon", english: "Who make mischief in the land, and mend not (their ways)", romanUrdu: "Jo zameen mein fasaad barpa karte hain aur koi islaah nahin karte”" },
    { number: 153, arabic: "قَالُوٓا۟ إِنَّمَآ أَنتَ مِنَ ٱلْمُسَحَّرِينَ", transliteration: "Qaloo innama anta mina almusahhareena", transliterationB: "Qaalooo innamaa anta minal musahhareen", english: "They said: \"Thou art only one of those bewitched", romanUrdu: "Unhon ne jawab diya “tu mehaz ek sehar-zadah (affected by magic) aadmi hai" },
    { number: 154, arabic: "مَآ أَنتَ إِلَّا بَشَرٌۭ مِّثْلُنَا فَأْتِ بِـَٔايَةٍ إِن كُنتَ مِنَ ٱلصَّٰدِقِينَ", transliteration: "Ma anta illa basharun mithluna fati biayatin in kunta mina alssadiqeena", transliterationB: "Maaa anta illaa basharum mislunaa faati bi Aayatin in kunta minas saadiqeen", english: "Thou art no more than a mortal like us: then bring us a Sign, if thou tellest the truth", romanUrdu: "Tu hum jaise ek Insaan ke siwa aur kya hai, laa koi nishani agar tu saccha hai”" },
    { number: 155, arabic: "قَالَ هَٰذِهِۦ نَاقَةٌۭ لَّهَا شِرْبٌۭ وَلَكُمْ شِرْبُ يَوْمٍۢ مَّعْلُومٍۢ", transliteration: "Qala hathihi naqatun laha shirbun walakum shirbu yawmin maAAloomin", transliterationB: "Qaala haazihee naaqatul lahaa shirbunw w alakum shirbu yawmim ma'loom", english: "He said: \"Here is a she-camel: she has a right of watering, and ye have a right of watering, (severally) on a day appointed", romanUrdu: "Saleh ne kaha “yeh ountni (she-camel) hai ek din iske peene ka hai aur ek din tum sab ke pani lenay ka" },
    { number: 156, arabic: "وَلَا تَمَسُّوهَا بِسُوٓءٍۢ فَيَأْخُذَكُمْ عَذَابُ يَوْمٍ عَظِيمٍۢ", transliteration: "Wala tamassooha bisooin fayakhuthakum AAathabu yawmin AAatheemin", transliterationB: "Wa laa tamassoohaa bisooo'in fa yaakhuzakum 'azaabu Yawmin 'Azeem", english: "Touch her not with harm, lest the Penalty of a Great Day seize you", romanUrdu: "Isko hargiz na chedhna(molest) warna ek baday din ka azaab tumko aa lega”" },
    { number: 157, arabic: "فَعَقَرُوهَا فَأَصْبَحُوا۟ نَٰدِمِينَ", transliteration: "FaAAaqarooha faasbahoo nadimeena", transliterationB: "Fa'aqaroohaa fa asbahoo naadimeen", english: "But they ham-strung her: then did they become full of regrets", romanUrdu: "Magar unhon ne iski kunchein kaat di (hamstrung her) aur aakhir-e-kaar pachtate reh gaye" },
    { number: 158, arabic: "فَأَخَذَهُمُ ٱلْعَذَابُ ۗ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ", transliteration: "Faakhathahumu alAAathabu inna fee thalika laayatan wama kana aktharuhum mumineena", transliterationB: "Fa akhazahumul 'azaab; inna fee zaalika la Aayah; wa maa kaana aksaruhum m'mineen", english: "But the Penalty seized them. Verily in this is a Sign: but most of them do not believe", romanUrdu: "Azaab ne unhein aa liya, yaqeenan ismein ek nishani hai, magar in mein se aksar maanne waley nahin" },
    { number: 159, arabic: "وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ", transliteration: "Wainna rabbaka lahuwa alAAazeezu alrraheemu", transliterationB: "Wa inna Rabbaka la Huwal 'Azeezur Raheem", english: "And verily thy Lord is He, the Exalted in Might, Most Merciful", romanUrdu: "Aur haqeeqat yeh hai ke tera Rubb zabardast bhi hai aur raheem bhi" },
    { number: 160, arabic: "كَذَّبَتْ قَوْمُ لُوطٍ ٱلْمُرْسَلِينَ", transliteration: "Kaththabat qawmu lootin almursaleena", transliterationB: "kazzabat qawmu Lootinil mursaleen", english: "The people of Lut rejected the messengers", romanUrdu: "Lut ki qaum ne Rasoolon ko jhutlaya" },
    { number: 161, arabic: "إِذْ قَالَ لَهُمْ أَخُوهُمْ لُوطٌ أَلَا تَتَّقُونَ", transliteration: "Ith qala lahum akhoohum lootun ala tattaqoona", transliterationB: "Iz qaala lahum akhoohum Lootun alaa tattaqoon", english: "Behold, their brother Lut said to them: \"Will ye not fear (Allah)", romanUrdu: "Yaad karo jabke unke bhai Lut ne unsey kaha tha “kya tum darte nahin" },
    { number: 162, arabic: "إِنِّى لَكُمْ رَسُولٌ أَمِينٌۭ", transliteration: "Innee lakum rasoolun ameenun", transliterationB: "Innee lakum rasoolun ameen", english: "I am to you a messenger worthy of all trust", romanUrdu: "Main tumhare liye ek amanat-daar Rasool hoon" },
    { number: 163, arabic: "فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ", transliteration: "Faittaqoo Allaha waateeAAooni", transliterationB: "Fattaqul laaha wa atee'oon", english: "So fear Allah and obey me", romanUrdu: "Lihaza tum Allah se daro aur meri itaat karo" },
    { number: 164, arabic: "وَمَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنْ أَجْرٍ ۖ إِنْ أَجْرِىَ إِلَّا عَلَىٰ رَبِّ ٱلْعَٰلَمِينَ", transliteration: "Wama asalukum AAalayhi min ajrin in ajriya illa AAala rabbi alAAalameena", transliterationB: "Wa maaa as'alukum 'alaihi min ajrin in ajriya illaa 'alaa Rabbil 'aalameen", english: "No reward do I ask of you for it: my reward is only from the lord of the Worlds", romanUrdu: "Main is kaam par tumse kisi ajar ka talib nahin hoon, mera ajar to Rabbul aalameen ke zimme hai" },
    { number: 165, arabic: "أَتَأْتُونَ ٱلذُّكْرَانَ مِنَ ٱلْعَٰلَمِينَ", transliteration: "Atatoona alththukrana mina alAAalameena", transliterationB: "Ataatoonaz zukraana minal 'aalameen", english: "Of all the creatures in the world, will ye approach males", romanUrdu: "Kya tum duniya ki makhlooq mein se Mardon ke paas jatey ho" },
    { number: 166, arabic: "وَتَذَرُونَ مَا خَلَقَ لَكُمْ رَبُّكُم مِّنْ أَزْوَٰجِكُم ۚ بَلْ أَنتُمْ قَوْمٌ عَادُونَ", transliteration: "Watatharoona ma khalaqa lakum rabbukum min azwajikum bal antum qawmun AAadoona", transliterationB: "Wa tazaroona maa khalaqa lakum Rabbukum min azwaajikum; bal antum qawmun 'aadoon", english: "And leave those whom Allah has created for you to be your mates? Nay, ye are a people transgressing (all limits)", romanUrdu: "Aur tumhari biwiyon mein tumhare Rubb ne tumhare liye jo kuch paida kiya hai usey chodh detey ho? Balke tum log to hadd se hi guzar gaye ho.”" },
    { number: 167, arabic: "قَالُوا۟ لَئِن لَّمْ تَنتَهِ يَٰلُوطُ لَتَكُونَنَّ مِنَ ٱلْمُخْرَجِينَ", transliteration: "Qaloo lain lam tantahi ya lootu latakoonanna mina almukhrajeena", transliterationB: "Qaloo la'il lam tantahi yaa Lootu latakoonanna minal mukhrajeen", english: "They said: \"If thou desist not, O Lut! thou wilt assuredly be cast out", romanUrdu: "Unhon ne kaha “ aey Lut” agar tu in baaton se baaz na aaya to jo log hamari bastiyon se nikale gaye hain unmein tu bhi shamil ho kar rahega”" },
    { number: 168, arabic: "قَالَ إِنِّى لِعَمَلِكُم مِّنَ ٱلْقَالِينَ", transliteration: "Qala innee liAAamalikum mina alqaleena", transliterationB: "Qaala innee li'amalikum minal qaaleen", english: "He said: \"I do detest your doings", romanUrdu: "Usne kaha “tumhare kartooton par jo log kudd (abhor/detest) rahey hain main un mein shamil hoon" },
    { number: 169, arabic: "رَبِّ نَجِّنِى وَأَهْلِى مِمَّا يَعْمَلُونَ", transliteration: "Rabbi najjinee waahlee mimma yaAAmaloona", transliterationB: "Rabbi najjjinee wa ahlee mimmmaa ya'maloon", english: "O my Lord! deliver me and my family from such things as they do", romanUrdu: "Aey parwardigar, mujhey aur mere ehal-o-ayaal (me and my people/ my family) ko inki badkirdariyon se nijaat de”" },
    { number: 170, arabic: "فَنَجَّيْنَٰهُ وَأَهْلَهُۥٓ أَجْمَعِينَ", transliteration: "Fanajjaynahu waahlahu ajmaAAeena", transliterationB: "Fanajjainaahu wa ahlahooo ajma'een", english: "So We delivered him and his family,- all", romanUrdu: "Aakhir e kaar humne usey aur uske sab ehal-o-ayaal ko bacha liya" },
    { number: 171, arabic: "إِلَّا عَجُوزًۭا فِى ٱلْغَٰبِرِينَ", transliteration: "Illa AAajoozan fee alghabireena", transliterationB: "Illaa 'ajoozan filghaabireen", english: "Except an old woman who lingered behind", romanUrdu: "Bajuz ek budiya ke jo peechey reh janey walon mein se thi" },
    { number: 172, arabic: "ثُمَّ دَمَّرْنَا ٱلْءَاخَرِينَ", transliteration: "Thumma dammarna alakhareena", transliterationB: "Summa dammarnal aa khareen", english: "But the rest We destroyed utterly", romanUrdu: "Phir baaqi maanda(rest) logon ko humne tabaah kardiya" },
    { number: 173, arabic: "وَأَمْطَرْنَا عَلَيْهِم مَّطَرًۭا ۖ فَسَآءَ مَطَرُ ٱلْمُنذَرِينَ", transliteration: "Waamtarna AAalayhim mataran fasaa mataru almunthareena", transliterationB: "Wa amtarnaa 'alaihim mataran fasaaa'a matarul munzareen", english: "We rained down on them a shower (of brimstone): and evil was the shower on those who were admonished (but heeded not)", romanUrdu: "Aur unpar barsayi ek barsaat, badi hi buri baarish thi jo un daraye janey walon par nazil hui" },
    { number: 174, arabic: "إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ", transliteration: "Inna fee thalika laayatan wama kana aktharuhum mumineena", transliterationB: "Inna fee zaalika la Aayah; wa maa kaana aksaruhum mu'mineen", english: "Verily in this is a Sign: but most of them do not believe", romanUrdu: "Yaqeenan ismein ek nishani hai, magar inmein se aksar maanne waley nahin" },
    { number: 175, arabic: "وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ", transliteration: "Wainna rabbaka lahuwa alAAazeezu alrraheemu", transliterationB: "Wa inna Rabbaka la Huwal 'Azeezur Raheem", english: "And verily thy Lord is He, the Exalted in Might Most Merciful", romanUrdu: "Aur haqeeqat yeh hai ke tera Rubb zabardast bhi hai aur raheem bhi" },
    { number: 176, arabic: "كَذَّبَ أَصْحَٰبُ لْـَٔيْكَةِ ٱلْمُرْسَلِينَ", transliteration: "Kaththaba ashabu alaykati almursaleena", transliterationB: "Kazzaba As haabul Aykatil mursaleen", english: "The Companions of the Wood rejected the messengers", romanUrdu: "Ashaab-ul-Aiyqah ne Rasoolon ko jhutlaya" },
    { number: 177, arabic: "إِذْ قَالَ لَهُمْ شُعَيْبٌ أَلَا تَتَّقُونَ", transliteration: "Ith qala lahum shuAAaybun ala tattaqoona", transliterationB: "Iz qaala lahum Shu'aybun alaa tattaqoon", english: "Behold, Shu'aib said to them: \"Will ye not fear (Allah)", romanUrdu: "Yaad karo jabke Shoaib ne unse kaha tha “kya tum darte nahin" },
    { number: 178, arabic: "إِنِّى لَكُمْ رَسُولٌ أَمِينٌۭ", transliteration: "Innee lakum rasoolun ameenun", transliterationB: "Innee lakum Rasoolun ameen", english: "I am to you a messenger worthy of all trust", romanUrdu: "Main tumhare liye ek amanat-daar Rasool hoon" },
    { number: 179, arabic: "فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ", transliteration: "Faittaqoo Allaha waateeAAooni", transliterationB: "Fattaqul laaha wa atee'oon", english: "So fear Allah and obey me", romanUrdu: "Lihaza tum Allah se daro aur meri itaat karo" },
    { number: 180, arabic: "وَمَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنْ أَجْرٍ ۖ إِنْ أَجْرِىَ إِلَّا عَلَىٰ رَبِّ ٱلْعَٰلَمِينَ", transliteration: "Wama asalukum AAalayhi min ajrin in ajriya illa AAala rabbi alAAalameena", transliterationB: "Wa maaa as'alukum 'alaihi min ajrin in ajriya illaa 'alaa Rabbil 'aalameen", english: "No reward do I ask of you for it: my reward is only from the Lord of the Worlds", romanUrdu: "Main is kaam par tumse kisi ajar ka talib nahin hoon, mera ajar to Rabbul aalameen ke zimme hai" },
    { number: 181, arabic: "۞ أَوْفُوا۟ ٱلْكَيْلَ وَلَا تَكُونُوا۟ مِنَ ٱلْمُخْسِرِينَ", transliteration: "Awfoo alkayla wala takoonoo mina almukhsireena", transliterationB: "Awful kaila wa laa takoonoo minal mukhsireen", english: "Give just measure, and cause no loss (to others by fraud)", romanUrdu: "Paimane theek bharo (Give full measure) aur kisi ko ghaata (less) na do" },
    { number: 182, arabic: "وَزِنُوا۟ بِٱلْقِسْطَاسِ ٱلْمُسْتَقِيمِ", transliteration: "Wazinoo bialqistasi almustaqeemi", transliterationB: "Wa zinoo bilqistaasil mustaqeem", english: "And weigh with scales true and upright", romanUrdu: "Saheeh tarazu se tolo" },
    { number: 183, arabic: "وَلَا تَبْخَسُوا۟ ٱلنَّاسَ أَشْيَآءَهُمْ وَلَا تَعْثَوْا۟ فِى ٱلْأَرْضِ مُفْسِدِينَ", transliteration: "Wala tabkhasoo alnnasa ashyaahum wala taAAthaw fee alardi mufsideena", transliterationB: "Wa laa tabkhasun naasa ashyaaa 'ahum wa laa ta'saw fil ardi mufsideen", english: "And withhold not things justly due to men, nor do evil in the land, working mischief", romanUrdu: "Aur logon ko unki cheezein kam na do, zameen mein fasaad na phaylate phiro" },
    { number: 184, arabic: "وَٱتَّقُوا۟ ٱلَّذِى خَلَقَكُمْ وَٱلْجِبِلَّةَ ٱلْأَوَّلِينَ", transliteration: "Waittaqoo allathee khalaqakum waaljibillata alawwaleena", transliterationB: "Wattaqul lazee khalaqakum waljibillatal awwaleen", english: "And fear Him Who created you and (who created) the generations before (you)", romanUrdu: "Aur us zaat ka khauff karo jisne tumhein aur guzishta nasalon ko paida kiya hai.”" },
    { number: 185, arabic: "قَالُوٓا۟ إِنَّمَآ أَنتَ مِنَ ٱلْمُسَحَّرِينَ", transliteration: "Qaloo innama anta mina almusahhareena", transliterationB: "Qaalooo innamaa anta minal musahhareen", english: "They said: \"Thou art only one of those bewitched", romanUrdu: "Unhon ne kaha “tu mehaz ek sehar zadah(affected by magic) aadmi hai" },
    { number: 186, arabic: "وَمَآ أَنتَ إِلَّا بَشَرٌۭ مِّثْلُنَا وَإِن نَّظُنُّكَ لَمِنَ ٱلْكَٰذِبِينَ", transliteration: "Wama anta illa basharun mithluna wain nathunnuka lamina alkathibeena", transliterationB: "Wa maaa anta illaa basharum mislunaa wa innazunnuka laminal kaazibeen", english: "Thou art no more than a mortal like us, and indeed we think thou art a liar", romanUrdu: "Aur tu kuch nahin magar ek Insaan hum hi jaisa, aur hum to tujhey bilkul jhoota samajhte hain" },
    { number: 187, arabic: "فَأَسْقِطْ عَلَيْنَا كِسَفًۭا مِّنَ ٱلسَّمَآءِ إِن كُنتَ مِنَ ٱلصَّٰدِقِينَ", transliteration: "Faasqit AAalayna kisafan mina alssamai in kunta mina alssadiqeena", transliterationB: "Fa asqit 'alainaa kisafam minas samaaa'i in kunta minas saadiqeen", english: "Now cause a piece of the sky to fall on us, if thou art truthful", romanUrdu: "Agar tu saccha hai to humpar aasmaan ka koi tukda gira de”" },
    { number: 188, arabic: "قَالَ رَبِّىٓ أَعْلَمُ بِمَا تَعْمَلُونَ", transliteration: "Qala rabbee aAAlamu bima taAAmaloona", transliterationB: "Qaala Rabbeee a'lamu bimaa ta'maloon", english: "He said: \"My Lord knows best what ye do", romanUrdu: "Shoaib ne kaha “ mera Rubb jaanta hai jo kuch tum kar rahey ho”" },
    { number: 189, arabic: "فَكَذَّبُوهُ فَأَخَذَهُمْ عَذَابُ يَوْمِ ٱلظُّلَّةِ ۚ إِنَّهُۥ كَانَ عَذَابَ يَوْمٍ عَظِيمٍ", transliteration: "Fakaththaboohu faakhathahum AAathabu yawmi alththullati innahu kana AAathaba yawmin AAatheemin", transliterationB: "Fakazzaboohu fa akhazahum 'azaabu Yawmiz zullah; innahoo kaana 'azaaba Yawmin 'Azeem", english: "But they rejected him. Then the punishment of a day of overshadowing gloom seized them, and that was the Penalty of a Great Day", romanUrdu: "Unhon ne usey jhutla diya, aakhir-e-kaar chatri waley din (Day of Canopy) ka azaab unpar aa gaya, aur woh baday hi khauf-naak din ka azaab tha" },
    { number: 190, arabic: "إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ", transliteration: "Inna fee thalika laayatan wama kana aktharuhum mumineena", transliterationB: "Inna fee zaalika la Aayah; wa maa kaana aksaruhum mu'mineen", english: "Verily in that is a Sign: but most of them do not believe", romanUrdu: "Yaqeenan ismein ek nishani hai, magar in mein se aksar log maanne waley nahin" },
    { number: 191, arabic: "وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ", transliteration: "Wainna rabbaka lahuwa alAAazeezu alrraheemu", transliterationB: "Wa inna Rabbaka la huwal 'Azeezur Raheem", english: "And verily thy Lord is He, the Exalted in Might, Most Merciful", romanUrdu: "Aur haqeeqat yeh hai ke tera Rubb zabardast bhi hai aur raheem bhi" },
    { number: 192, arabic: "وَإِنَّهُۥ لَتَنزِيلُ رَبِّ ٱلْعَٰلَمِينَ", transliteration: "Wainnahu latanzeelu rabbi alAAalameena", transliterationB: "Wa innahoo latanzeelu Rabbil 'aalameen", english: "Verily this is a Revelation from the Lord of the Worlds", romanUrdu: "Yeh Rabbul Aalameen ki nazil karda cheez hai" },
    { number: 193, arabic: "نَزَلَ بِهِ ٱلرُّوحُ ٱلْأَمِينُ", transliteration: "Nazala bihi alrroohu alameenu", transliterationB: "Nazala bihir Roohul Ameen", english: "With it came down the spirit of Faith and Truth", romanUrdu: "Isey lekar tere dil par amanat-daar rooh utri hai" },
    { number: 194, arabic: "عَلَىٰ قَلْبِكَ لِتَكُونَ مِنَ ٱلْمُنذِرِينَ", transliteration: "AAala qalbika litakoona mina almunthireena", transliterationB: "Alaa qalbika litakoona minal munzireen", english: "To thy heart and mind, that thou mayest admonish", romanUrdu: "Taa-ke tu un logon mein shamil ho jo (khuda ki taraf se khalq-e-khuda ko) mutanabbeh (warn) karne waley hain" },
    { number: 195, arabic: "بِلِسَانٍ عَرَبِىٍّۢ مُّبِينٍۢ", transliteration: "Bilisanin AAarabiyyin mubeenin", transliterationB: "Bilisaanin 'Arabiyyim mubeen", english: "In the perspicuous Arabic tongue", romanUrdu: "Saaf saaf arabi zubaan mein" },
    { number: 196, arabic: "وَإِنَّهُۥ لَفِى زُبُرِ ٱلْأَوَّلِينَ", transliteration: "Wainnahu lafee zuburi alawwaleena", transliterationB: "Wa innahoo lafee Zuburil awwaleen", english: "Without doubt it is (announced) in the mystic Books of former peoples", romanUrdu: "Aur agley logo ki kitaabon mein bhi yeh maujood hai" },
    { number: 197, arabic: "أَوَلَمْ يَكُن لَّهُمْ ءَايَةً أَن يَعْلَمَهُۥ عُلَمَٰٓؤُا۟ بَنِىٓ إِسْرَٰٓءِيلَ", transliteration: "Awalam yakun lahum ayatan an yaAAlamahu AAulamao banee israeela", transliterationB: "Awalam yakul lahum Aayatan ai ya'lamahoo 'ulamaaa'u Baneee Israaa'eel", english: "Is it not a Sign to them that the Learned of the Children of Israel knew it (as true)", romanUrdu: "Kya in (ehle Makkah) ke liye yeh koi nishani nahin hai ke isey ulema-e-bani Israel jaante hain" },
    { number: 198, arabic: "وَلَوْ نَزَّلْنَٰهُ عَلَىٰ بَعْضِ ٱلْأَعْجَمِينَ", transliteration: "Walaw nazzalnahu AAala baAAdi alaAAjameena", transliterationB: "Wa law nazzalnaahu 'alaa ba'dil a'jameen", english: "Had We revealed it to any of the non-Arabs", romanUrdu: "(Lekin inki hatdarmi ka haal yeh hai ke) agar hum isey kisi ajami (non-arab) par bhi nazil kar detey" },
    { number: 199, arabic: "فَقَرَأَهُۥ عَلَيْهِم مَّا كَانُوا۟ بِهِۦ مُؤْمِنِينَ", transliteration: "Faqaraahu AAalayhim ma kanoo bihi mumineena", transliterationB: "Faqara ahoo 'alaihim maa kaanoo bihee mu'mineen", english: "And had he recited it to them, they would not have believed in it", romanUrdu: "Aur yeh (faseeh arabi kalaam) woh inko padh kar sunata tab bhi yeh maan kar na detey" },
    { number: 200, arabic: "كَذَٰلِكَ سَلَكْنَٰهُ فِى قُلُوبِ ٱلْمُجْرِمِينَ", transliteration: "Kathalika salaknahu fee quloobi almujrimeena", transliterationB: "Kazaalika salaknaahu fee quloobil mujrimeen", english: "Thus have We caused it to enter the hearts of the sinners", romanUrdu: "Isi tarah humne is (zikr) ko mujrimon ke dilon mein guzara hai" },
    { number: 201, arabic: "لَا يُؤْمِنُونَ بِهِۦ حَتَّىٰ يَرَوُا۟ ٱلْعَذَابَ ٱلْأَلِيمَ", transliteration: "La yuminoona bihi hatta yarawoo alAAathaba alaleema", transliterationB: "Laa yu'minoona bihee hattaa yarawul 'azaabal aleem", english: "They will not believe in it until they see the grievous Penalty", romanUrdu: "Woh ispar iman nahin latey jab tak azaab e aleem na dekh lein" },
    { number: 202, arabic: "فَيَأْتِيَهُم بَغْتَةًۭ وَهُمْ لَا يَشْعُرُونَ", transliteration: "Fayatiyahum baghtatan wahum la yashAAuroona", transliterationB: "Fayaatiyahum baghtatanw wa hum laa yash'uroon", english: "But the (Penalty) will come to them of a sudden, while they perceive it not", romanUrdu: "Phir jab woh be-khabari mein unpar aa padta hai" },
    { number: 203, arabic: "فَيَقُولُوا۟ هَلْ نَحْنُ مُنظَرُونَ", transliteration: "Fayaqooloo hal nahnu muntharoona", transliterationB: "Fa yaqooloo hal nahnu munzaroon", english: "Then they will say: \"Shall we be respited", romanUrdu: "Us waqt kehte hain “ke kya ab humein kuch mohalat mil sakti hai?”" },
    { number: 204, arabic: "أَفَبِعَذَابِنَا يَسْتَعْجِلُونَ", transliteration: "AfabiAAathabina yastaAAjiloona", transliterationB: "Aafabi 'azaabinaa yasta'jiloon", english: "Do they then ask for Our Penalty to be hastened on", romanUrdu: "To kya yeh log hamare azab ke liye jaldi macha rahey hain" },
    { number: 205, arabic: "أَفَرَءَيْتَ إِن مَّتَّعْنَٰهُمْ سِنِينَ", transliteration: "Afaraayta in mattaAAnahum sineena", transliterationB: "Aara'aita im matta'naahum sineen", english: "Seest thou? If We do let them enjoy (this life) for a few years", romanUrdu: "Tumne kuch gaur kiya , agar hum inhein barason tak aish karne ki mohalat bhi de dein" },
    { number: 206, arabic: "ثُمَّ جَآءَهُم مَّا كَانُوا۟ يُوعَدُونَ", transliteration: "Thumma jaahum ma kanoo yooAAadoona", transliterationB: "Summa jaaa'ahum maa kaanoo yoo'adoon", english: "Yet there comes to them at length the (Punishment) which they were promised", romanUrdu: "Aur phir wahi cheez unpar aa jaye jissey inhein daraya jaa raha hai" },
    { number: 207, arabic: "مَآ أَغْنَىٰ عَنْهُم مَّا كَانُوا۟ يُمَتَّعُونَ", transliteration: "Ma aghna AAanhum ma kanoo yumattaAAoona", transliterationB: "Maaa aghnaaa 'anhum maa kaanoo yumaatoo'oon", english: "It will profit them not that they enjoyed (this life)", romanUrdu: "To woh saamaan-e-zeist (provisions of life) jo unko mila hua hai inke kis kaam aayega" },
    { number: 208, arabic: "وَمَآ أَهْلَكْنَا مِن قَرْيَةٍ إِلَّا لَهَا مُنذِرُونَ", transliteration: "Wama ahlakna min qaryatin illa laha munthiroona", transliterationB: "Wa maaa ahlaknaa min qaryatin illaa lahaa munziroon", english: "Never did We destroy a population, but had its warners", romanUrdu: "(Dekho) humne kabhi kisi basti ko iske bagair halaak nahin kiya ke uske liye khabardar karne waley haqq e naseehat ada karne ko maujood thay" },
    { number: 209, arabic: "ذِكْرَىٰ وَمَا كُنَّا ظَٰلِمِينَ", transliteration: "Thikra wama kunna thalimeena", transliterationB: "Zikraa wa maa kunnaa zaalimeen", english: "By way of reminder; and We never are unjust", romanUrdu: "Aur hum zaalim na thay" },
    { number: 210, arabic: "وَمَا تَنَزَّلَتْ بِهِ ٱلشَّيَٰطِينُ", transliteration: "Wama tanazzalat bihi alshshayateenu", transliterationB: "Wa maa tanazzalat bihish Shayaateen", english: "No evil ones have brought down this (Revelation)", romanUrdu: "Is (kitaab e mubeen) ko shayateen lekar nahin utray hain" },
    { number: 211, arabic: "وَمَا يَنۢبَغِى لَهُمْ وَمَا يَسْتَطِيعُونَ", transliteration: "Wama yanbaghee lahum wama yastateeAAoona", transliterationB: "Wa maa yambaghee lahum wa maa yastatee'oon", english: "It would neither suit them nor would they be able (to produce it)", romanUrdu: "Na yeh kaam unko sajta hai, aur na woh aisa kar hi sakte hain" },
    { number: 212, arabic: "إِنَّهُمْ عَنِ ٱلسَّمْعِ لَمَعْزُولُونَ", transliteration: "Innahum AAani alssamAAi lamaAAzooloona", transliterationB: "Innahum 'anis sam'i lama'zooloon", english: "Indeed they have been removed far from even (a chance of) hearing it", romanUrdu: "Woh to iski samaat (hearing) tak se door rakkhey gaye hain" },
    { number: 213, arabic: "فَلَا تَدْعُ مَعَ ٱللَّهِ إِلَٰهًا ءَاخَرَ فَتَكُونَ مِنَ ٱلْمُعَذَّبِينَ", transliteration: "Fala tadAAu maAAa Allahi ilahan akhara fatakoona mina almuAAaththabeena", transliterationB: "Falaa tad'u ma'al laahi ilaahan aakhara fatakoona minal mu'azzabeen", english: "So call not on any other god with Allah, or thou wilt be among those under the Penalty", romanUrdu: "Pas (aey Muhammad), Allah ke saath kisi dusre mabood ko na pukaro, warna tum bhi saza paaney walon mein shamil ho jaogey" },
    { number: 214, arabic: "وَأَنذِرْ عَشِيرَتَكَ ٱلْأَقْرَبِينَ", transliteration: "Waanthir AAasheerataka alaqrabeena", transliterationB: "Wa anzir 'asheeratakal aqrabeen", english: "And admonish thy nearest kinsmen", romanUrdu: "Apne qareeb-tareen rishtedaaron ko darao" },
    { number: 215, arabic: "وَٱخْفِضْ جَنَاحَكَ لِمَنِ ٱتَّبَعَكَ مِنَ ٱلْمُؤْمِنِينَ", transliteration: "Waikhfid janahaka limani ittabaAAaka mina almumineena", transliterationB: "Wakhfid janaahaka limanit taba 'aka minal mu'mineen", english: "And lower thy wing to the Believers who follow thee", romanUrdu: "Aur iman laney walon mein se jo log tumhari pairwi ikhtiyar karein unke saath tawazo (humble/kindness) se pesh aao" },
    { number: 216, arabic: "فَإِنْ عَصَوْكَ فَقُلْ إِنِّى بَرِىٓءٌۭ مِّمَّا تَعْمَلُونَ", transliteration: "Fain AAasawka faqul innee bareeon mimma taAAmaloona", transliterationB: "Fa in asawka faqul innee bareee'um mimmmaa ta'maloon", english: "Then if they disobey thee, say: \"I am free (of responsibility) for what ye do", romanUrdu: "Lekin agar woh tumhari nafarmaani karein to unsey kehdo ke jo kuch tum karte ho ussey main bari-uz-zimma (not responsible) hoon" },
    { number: 217, arabic: "وَتَوَكَّلْ عَلَى ٱلْعَزِيزِ ٱلرَّحِيمِ", transliteration: "Watawakkal AAala alAAazeezi alrraheemi", transliterationB: "Wa tawakkal alal 'Azeezir Raheem", english: "And put thy trust on the Exalted in Might, the Merciful", romanUrdu: "Aur us zabardast aur raheem par tawakkul(bharosa) karo" },
    { number: 218, arabic: "ٱلَّذِى يَرَىٰكَ حِينَ تَقُومُ", transliteration: "Allathee yaraka heena taqoomu", transliterationB: "Allazee yaraaka heena taqoom", english: "Who seeth thee standing forth (in prayer)", romanUrdu: "Jo tumhein us waqt dekh raha hota hai jab tum uthte ho" },
    { number: 219, arabic: "وَتَقَلُّبَكَ فِى ٱلسَّٰجِدِينَ", transliteration: "Wataqallubaka fee alssajideena", transliterationB: "Wa taqallubaka fis saajideen", english: "And thy movements among those who prostrate themselves", romanUrdu: "Aur sajda guzaar logon mein tumhari naqal o harakat par nigaah rakhta hai" },
    { number: 220, arabic: "إِنَّهُۥ هُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ", transliteration: "Innahu huwa alssameeAAu alAAaleemu", transliterationB: "Innahoo Huwas Samee'ul 'Aleem", english: "For it is He Who heareth and knoweth all things", romanUrdu: "Woh sab kuch sunnay aur jaanne wala hai" },
    { number: 221, arabic: "هَلْ أُنَبِّئُكُمْ عَلَىٰ مَن تَنَزَّلُ ٱلشَّيَٰطِينُ", transliteration: "Hal onabbiokum AAala man tanazzalu alshshayateenu", transliterationB: "Hal unabbi'ukum 'alaa man tanazzalush Shayaateen", english: "Shall I inform you, (O people!), on whom it is that the evil ones descend", romanUrdu: "Logon, kya main tumhein bataon ke shayateen kis par utra karte hain" },
    { number: 222, arabic: "تَنَزَّلُ عَلَىٰ كُلِّ أَفَّاكٍ أَثِيمٍۢ", transliteration: "Tanazzalu AAala kulli affakin atheemin", transliterationB: "Tanazzalu 'alaa kulli affaakin aseem", english: "They descend on every lying, wicked person", romanUrdu: "Woh har chaal saaz, badhkaar par utra karte hain" },
    { number: 223, arabic: "يُلْقُونَ ٱلسَّمْعَ وَأَكْثَرُهُمْ كَٰذِبُونَ", transliteration: "Yulqoona alssamAAa waaktharuhum kathiboona", transliterationB: "Yulqoonas sam'a wa aksaruhum aaziboon", english: "(Into whose ears) they pour hearsay vanities, and most of them are liars", romanUrdu: "Suni sunayi baatein kaano mein phoonkte hain, aur unmein se aksar jhootey hotay hain" },
    { number: 224, arabic: "وَٱلشُّعَرَآءُ يَتَّبِعُهُمُ ٱلْغَاوُۥنَ", transliteration: "WaalshshuAAarao yattabiAAuhumu alghawoona", transliterationB: "Washshu 'araaa'u yattabi 'uhumul ghaawoon", english: "And the Poets,- It is those straying in Evil, who follow them", romanUrdu: "Rahey shuaraa (poets), to unke peechey behke huey log chala karte hain" },
    { number: 225, arabic: "أَلَمْ تَرَ أَنَّهُمْ فِى كُلِّ وَادٍۢ يَهِيمُونَ", transliteration: "Alam tara annahum fee kulli wadin yaheemoona", transliterationB: "Alam tara annahum fee kulli waadiny yaheemoon", english: "Seest thou not that they wander distracted in every valley", romanUrdu: "Kya tum dekhte nahin ho ke woh har waadi (valley) mein bhatakte hain" },
    { number: 226, arabic: "وَأَنَّهُمْ يَقُولُونَ مَا لَا يَفْعَلُونَ", transliteration: "Waannahum yaqooloona ma la yafAAaloona", transliterationB: "Wa annahum yaqooloona ma laa yaf'aloon", english: "And that they say what they practise not", romanUrdu: "Aur aisi baatein kehte hain jo karte nahin hain" },
    { number: 227, arabic: "إِلَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ وَذَكَرُوا۟ ٱللَّهَ كَثِيرًۭا وَٱنتَصَرُوا۟ مِنۢ بَعْدِ مَا ظُلِمُوا۟ ۗ وَسَيَعْلَمُ ٱلَّذِينَ ظَلَمُوٓا۟ أَىَّ مُنقَلَبٍۢ يَنقَلِبُونَ", transliteration: "Illa allatheena amanoo waAAamiloo alssalihati wathakaroo Allaha katheeran waintasaroo min baAAdi ma thulimoo wasayaAAlamu allatheena thalamoo ayya munqalabin yanqaliboona", transliterationB: "Illal lazeena aamanoo w a'amilus saalihaati wa zakarul laaha kaseeranw wantasaroo mim ba'di maa zulimoo; wa saya'lamul lazeena zalamooo aiya munqalbiny yanqaliboon", english: "Except those who believe, work righteousness, engage much in the remembrance of Allah, and defend themselves only after they are unjustly attacked. And soon will the unjust assailants know what vicissitudes their affairs will take", romanUrdu: "Bajuz un logon ke jo iman laye aur jinhon ne neik amal kiye aur Allah ko kasrat se yaad kiya aur jab unpar zulm kiya gaya to sirf badla le liye, aur zulm karne walon ko anqareeb maloom ho jayega ke woh kis anjaam se do-chaar hotay hain" }
  ]
};
